// ============ الحالة ============
const S = {
  cfg: { subject:'موضوع عام', diff:'سهل', qCount:10 },
  transcript: '',
  relevantWords: [],   // كلمات مفتاحية فقط
  sentences: [],
  concepts: [],        // مفاهيم مفهومة
  questions: [],
  exam: { idx:0, answers:[], timer:0, int:null }
};

const $ = id => document.getElementById(id);
const L = (ar,...vars)=>ar.reduce((s,a,i)=>s+a+(vars[i]||''),'');

// ============ Settings ============
document.querySelectorAll('[data-diff]').forEach(c => c.addEventListener('click', () => {
  document.querySelectorAll('[data-diff]').forEach(x=>x.classList.remove('active'));
  c.classList.add('active');
  S.cfg.diff = c.dataset.diff;
}));
document.querySelectorAll('[data-q]').forEach(c => c.addEventListener('click', () => {
  document.querySelectorAll('[data-q]').forEach(x=>x.classList.remove('active'));
  c.classList.add('active');
  S.cfg.qCount = parseInt(c.dataset.q);
}));
$('subjectInput').addEventListener('input', e => S.cfg.subject = e.target.value || 'موضوع عام');

// ============ Navigation ============
function go(id){
  if(S.exam.int && id!=='examScreen'){clearInterval(S.exam.int);S.exam.int=null;}
  document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));
  $(id).classList.add('active');
  window.scrollTo({top:0,behavior:'smooth'});
}
document.querySelectorAll('[data-go]').forEach(el=>el.addEventListener('click',()=>go(el.dataset.go)));

// ============ Theme ============
$('themeToggle').addEventListener('click',()=>{
  const h=document.documentElement,n=h.dataset.theme==='dark'?'light':'dark';
  h.dataset.theme=n;$('themeIcon') && ($('themeIcon').textContent=n==='dark'?'🌙':'☀️');
  $('themeToggle').textContent=n==='dark'?'🌙':'☀️';
  localStorage.setItem('theme',n);
});
if(localStorage.getItem('theme')){document.documentElement.dataset.theme=localStorage.getItem('theme');$('themeToggle').textContent=localStorage.getItem('theme')==='dark'?'🌙':'☀️';}

// ============ Toasts ============
function toast(msg,type=''){const t=$('toast');t.textContent=msg;t.className='toast show '+type;setTimeout(()=>t.className='toast',2400);}

// ============ شاشة التسجيل - Web Speech ============
let recognition = null;
let isRecording = false;
let recTimerStart = 0;
let recInterval = null;

function setupSpeech(){
  if(!('webkitSpeechRecognition' in window) && !('SpeechRecognition' in window)){
    toast('المتصفح لا يدعم التعرف على الصوت. استخدم الكتابة','warn');
    go('textScreen');
    return false;
  }
  const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
  recognition = new SR();
  recognition.lang = 'ar-SA';
  recognition.continuous = true;
  recognition.interimResults = true;
  recognition.maxAlternatives = 1;

  let finalTxt = '';
  recognition.onresult = (e) => {
    let interim = '';
    for(let i=e.resultIndex; i<e.results.length; i++){
      const r = e.results[i];
      if(r.isFinal) finalTxt += r[0].transcript + ' ';
      else interim += r[0].transcript;
    }
    S.transcript = finalTxt;
    $('transcript').innerHTML = L(
      '<span class="final">', finalTxt, '</span>',
      interim ? '<span class="interim"> '+interim+'</span>' : ''
    );
    updateWordCount();
    autoScroll();
    if(finalTxt.trim().length > 30) $('btnFinish').disabled = false;
  };
  recognition.onerror = (e) => {
    console.error('Speech error:', e.error);
    if(e.error==='not-allowed') toast('السماح بالميكروفون مطلوب','err');
    stopRecording();
  };
  recognition.onend = () => {
    if(isRecording){
      // إعادة تشغيل تلقائياً (المتصفح يوقف أحياناً)
      try{recognition.start();}catch(e){}
    }
  };
  return true;
}

function autoScroll(){
  const t = $('transcript');
  t.scrollTop = t.scrollHeight;
}

function updateWordCount(){
  const words = S.transcript.trim().split(/\s+/).filter(w=>w.length>0);
  $('wordCount').textContent = words.length;
}

function startRecording(){
  if(!recognition) {
    if(!setupSpeech()) return;
  }
  try{
    recognition.start();
    isRecording = true;
    $('micBtn').classList.add('recording');
    document.querySelector('.pulse-ring').classList.add('active');
    $('recStatusText') && ($('recStatusText').textContent='🔴 جاري الاستماع... تكلم بحرية');
    $('rec-status-text').textContent='🔴 جاري الاستماع... تكلم بحرية';
    recTimerStart = Date.now();
    recInterval = setInterval(()=>{
      const sec = Math.floor((Date.now()-recTimerStart)/1000);
      const m = String(Math.floor(sec/60)).padStart(2,'0');
      const s = String(sec%60).padStart(2,'0');
      $('recTimer').textContent = m+':'+s;
    },1000);
    $('btnFinish').disabled = true;
  }catch(e){toast('لا يمكن بدء التسجيل','err');}
}

function stopRecording(){
  if(recognition && isRecording){
    isRecording = false;
    try{recognition.stop();}catch(e){}
    $('micBtn').classList.remove('recording');
    document.querySelector('.pulse-ring').classList.remove('active');
    if(recInterval){clearInterval(recInterval);recInterval=null;}
    $('rec-status-text').textContent='⏸️ متوقف - اضغط لإعادة التسجيل';
  }
}

function toggleRecording(){
  if(isRecording) stopRecording();
  else startRecording();
}

$('micBtn').addEventListener('click', toggleRecording);
$('btnClear').addEventListener('click', () => {
  if(!confirm('مسح كل ما قلته؟')) return;
  S.transcript = '';
  $('transcript').innerHTML = '<span class="placeholder">النص يظهر هنا أثناء الكلام...</span>';
  $('wordCount').textContent = '0';
  $('btnFinish').disabled = true;
});
$('backRecord').addEventListener('click', ()=>{
  stopRecording();
  go('homeScreen');
});

// ============ شاشة الكتابة ============
const ti = $('textInput');
ti.addEventListener('input', () => {
  const txt = ti.value;
  S.transcript = txt;
  const words = txt.trim().split(/\s+/).filter(w=>w.length>0);
  const sents = txt.split(/[.!?؟।]+/).filter(s=>s.trim().length>10);
  $('textWordCount').textContent = words.length;
  $('textCharCount').textContent = txt.length;
  $('textSentCount').textContent = sents.length;
  $('textAnalyze').disabled = words.length < 20;
});
$('textClear').addEventListener('click', ()=>{
  if(!confirm('مسح كل النص؟')) return;
  ti.value='';
  ti.dispatchEvent(new Event('input'));
});

// ============ دالة للتحقق من التسجيل أولاً ============
$('goRecord').addEventListener('click', () => {
  $('recordTitle').textContent = 'سجّل شرحك لـ: '+S.cfg.subject;
  go('recordScreen');
  setTimeout(()=>{
    if(!recognition) setupSpeech();
    if(!recognition) return; // fallback
    toast('اضغط الميكروفون لبدء التسجيل');
  },300);
});
$('goText').addEventListener('click', () => {
  $('textInput').value = '';
  ti.dispatchEvent(new Event('input'));
  go('textScreen');
});

// ============ المحلل النصي - بدون APIs خارجية ============
// الكلمات الشائعة العربية + الانجليزية (نحذفها من "المهمة")
const STOPWORDS = new Set([
  // عربي
  'في','من','إلى','على','عن','مع','هذا','هذه','ذلك','تلك','التي','الذي','الذين','اللتي','اللاتي','اللذان','هما','هم','هن','أن','إن','كان','كانت','كانوا','يكون','تكون','أكون','نكون','كل','بعض','جميع','غير','جدا','أكثر','أقل','كما','إذا','إذ','حين','حتى','لكن','بل','أو','ثم','إنما','قد','لقد','لقد','ليس','ليست','يجب','يجب','ينبغي','كما','هنا','هناك','عند','بين','فوق','تحت','أمام','خلف','بعد','قبل','حين','متى','أين','كيف','لماذا','ماذا','من','أي','كم','أي','كلا','كلتا','هكذا','كذلك','أيضا','أيضًا','الآن','اليوم','الذى','الذى','سوف','لقد','أنت','أنتم','أنتما','أنا','نحن','هو','هي','كتاب','يقول','قل','قال','تقول','نعم','لا','ليس','ليسوا','هناك','هنالك','يمكن','تستطيع','استطيع','وال','والـ','على','إليه','منه','منها','فيه','فيها','به','بها','له','لها','لهم','إليهم','اليهم','إليهم','لدي','لديه','لديها','ايضا','ربما','كثير','قليلا','جدا','تماما','كثيرا','بعض','عدة','بعض','لكن','غير','سوى','إلا','ماعدا','ما','هو','هي','ابي','امي','انا','تعرف','تعرفون','اعرف','نعرف','الذى','احد','كل','كلا','كلتا','يجب','ينبغي','كان','كانت','صاحب','صاحبة','جد','جدة','ابن','ابنة','اخ','اخت'
]);

// فلتر الكلمات
function cleanWord(w){
  return w.replace(/[^\u0600-\u06FFa-zA-Z0-9]/g,'').trim();
}

function extractKeywords(text, max = 20){
  const words = text.split(/\s+/).map(cleanWord).filter(w=>w.length>=3 && !STOPWORDS.has(w) && !/^\d+$/.test(w));
  const freq = {};
  words.forEach(w => freq[w] = (freq[w]||0) + 1);
  // تكرار متجاور = تعزيز
  const bigrams = {};
  for(let i=0; i<words.length-1; i++){
    const bg = words[i]+' '+words[i+1];
    if(!STOPWORDS.has(words[i]) && !STOPWORDS.has(words[i+1])){
      bigrams[bg] = (bigrams[bg]||0) + 2; // وزن أعلى
    }
  }
  // ندمج
  const all = {};
  Object.entries(freq).forEach(([w,c])=>all[w]=c);
  Object.entries(bigrams).forEach(([w,c])=>all[w]=c);
  return Object.entries(all)
    .sort((a,b)=>b[1]-a[1])
    .slice(0, max)
    .map(([w])=>w);
}

// استخراج جمل بمعلومات (تذكر علاقة بين مفهومين)
function extractInformativeSentences(text, max=15){
  const sents = text.split(/[.!؟\n]+/).map(s=>s.trim()).filter(s=>s.length>=20 && s.length<=200);
  return sents.slice(0, max);
}

function splitImportantSentences(sentences){
  // جمل فيها قول/تعريف/علاقة
  return sentences.filter(s => {
    const l = s.toLowerCase();
    return /(هو|هي|هما|يعني|تعرف|بمعنى|يطلق على|يعرف|تستخدم|يستخدم|نستعمل|نستخ|يسمى|تسمى|بسبب|نتيجة|لذلك|حيث|إذن|لذا|أهم|أكثر|أقل|أكبر|أصغر|أفضل|أسرع|بطيء|قوي|ضعيف)/.test(s);
  });
}

// استخراج "مفاهيم" (لها كلمات مهمة + لها جملة مرتبطة)
function extractConcepts(keywords, sentences){
  const concepts = [];
  keywords.slice(0, 15).forEach(kw => {
    const related = sentences.find(s => s.includes(kw));
    if(related){
      concepts.push({
        term: kw,
        context: related
      });
    }
  });
  return concepts.slice(0, 10);
}

// ============ توليد الامتحان ============
function generateQuestions(){
  const text = S.transcript;
  const keywords = extractKeywords(text, 25);
  const allSents = extractInformativeSentences(text, 30);
  console.log('keywords:',keywords);
  console.log('sents:',allSents.length);

  let questions = [];
  const total = S.cfg.qCount;
  const targetMCQ = Math.floor(total * 0.4);
  const targetFill = Math.floor(total * 0.25);
  const targetTF = Math.floor(total * 0.2);
  const targetEssay = total - targetMCQ - targetFill - targetTF;

  // 1. أسئلة MCQ - من جمل فيها كلمات مهمة
  let mcqAttempts = 0;
  while(questions.filter(q=>q.type==='mcq').length < targetMCQ && mcqAttempts < allSents.length*2){
    const sent = allSents[Math.floor(Math.random()*allSents.length)];
    if(!sent || sent.length<25) {mcqAttempts++;continue;}

    // ابحث عن كلمة مهمة في الجملة
    const wordsInSent = sent.split(/\s+/).map(cleanWord).filter(w=>w.length>=3);
    const kwInSent = keywords.filter(k => sent.includes(k));

    if(kwInSent.length === 0){mcqAttempts++;continue;}

    const correctWord = kwInSent[0];
    // أنشئ MCQ: "ماذا يقصد بـ 'كلمة'؟" أو "في الجملة: '...' ماذا تعني 'كلمة'؟"
    const sentShort = sent.length > 100 ? sent.substring(0, 100) + '...' : sent;

    // أنشئ تشتيتات (إجابات خاطئة) من كلمات مفتاحية أخرى
    const distractors = [];
    const otherKw = keywords.filter(k => k !== correctWord && !correctWord.includes(k) && !k.includes(correctWord));
    while(distractors.length < 3 && otherKw.length){
      const i = Math.floor(Math.random()*otherKw.length);
      const d = otherKw.splice(i,1)[0];
      if(!distractors.includes(d)) distractors.push(d);
    }
    while(distractors.length < 3){
      distractors.push('خيار آخر');
    }

    const opts = [correctWord, ...distractors.slice(0,3)];
    // خلط
    const shuffled = opts.slice().sort(()=>Math.random()-.5);
    const correctIdx = shuffled.indexOf(correctWord);

    questions.push({
      type: 'mcq',
      q: L('في شرحك لـ "<em>', S.cfg.subject, '</em>" ذكرت:<br>«<em>', sentShort, '</em>»<br><br>أي من التالي يتعلق بهذه الجملة؟'),
      opts: shuffled,
      idx: correctIdx,
      exp: 'ذكرتها في شرحك: «'+sent+'»'
    });
    mcqAttempts++;
  }

  // 2. املأ الفراغ
  let fillAttempts = 0;
  while(questions.filter(q=>q.type==='fill').length < targetFill && fillAttempts < allSents.length*2){
    const sent = allSents[Math.floor(Math.random()*allSents.length)];
    if(!sent || sent.length<25) {fillAttempts++;continue;}
    const kwInSent = keywords.filter(k => sent.includes(k) && k.length>=4);
    if(kwInSent.length === 0) {fillAttempts++;continue;}

    const word = kwInSent[0];
    const blanked = sent.replace(new RegExp('\\b'+word+'\\b','i'), '_____');
    if(!blanked.includes('_____')) {fillAttempts++;continue;}
    questions.push({
      type: 'fill',
      q: L('أكمل الفراغ من شرحك:<br><br>«<em>', blanked, '</em>»'),
      ans: word,
      exp: 'الكلمة الصحيحة: «'+word+'» من جملتك الأصلية'
    });
    fillAttempts++;
  }

  // 3. صح / خطأ
  let tfAttempts = 0;
  while(questions.filter(q=>q.type==='tf').length < targetTF && tfAttempts < allSents.length*3){
    const sent = allSents[Math.floor(Math.random()*allSents.length)];
    if(!sent || sent.length<25) {tfAttempts++;continue;}
    const direction = Math.random() < 0.5;

    if(direction){
      // صح: جملة من شرحه
      questions.push({
        type: 'tf',
        q: L('هل قلت في شرحك:<br>«<em>', sent, '</em>»؟'),
        ans: true,
        exp: 'نعم، هذه الجملة من شرحك'
      });
    } else {
      // خطأ: نعكس كلمة في الجملة
      const kwInSent = keywords.filter(k => sent.includes(k) && k.length>=4);
      if(kwInSent.length === 0){tfAttempts++;continue;}
      const w = kwInSent[0];
      // اختر كلمة بديلة من الكلمات المفتاحية
      const otherKw = keywords.filter(k => k!==w && !w.includes(k) && !k.includes(w));
      if(otherKw.length === 0){tfAttempts++;continue;}
      const wrong = otherKw[Math.floor(Math.random()*otherKw.length)];
      const altered = sent.replace(w, wrong);
      if(altered === sent){tfAttempts++;continue;}
      questions.push({
        type: 'tf',
        q: L('هل قلت في شرحك:<br>«<em>', altered, '</em>»؟'),
        ans: false,
        exp: 'هذه الجملة معدّلة، الجملة الأصلية: «'+sent+'»'
      });
    }
    tfAttempts++;
  }

  // 4. مقالي
  let essayAttempts = 0;
  const usedKw = [];
  while(questions.filter(q=>q.type==='essay').length < targetEssay && essayAttempts < keywords.length*2){
    const kw = keywords[Math.floor(Math.random()*keywords.length)];
    if(usedKw.includes(kw)){essayAttempts++;continue;}
    usedKw.push(kw);
    if(!kw || kw.length<3){essayAttempts++;continue;}
    const sent = allSents.find(s => s.includes(kw)) || '';
    questions.push({
      type: 'essay',
      q: L('اشرح بكلماتك مفهوم «<em>', kw, '</em>» كما ذكرته.<br><small style="color:var(--text-2)">استخدم الجملة الأصلية كدليل.</small>'),
      ref: kw,
      refSent: sent,
      exp: 'ذكرتها في شرحك: «'+(sent||kw)+'»'
    });
    essayAttempts++;
  }

  // إذا ما اكتمل العدد - نسد بنسخ عشوائية
  while(questions.length < total && keywords.length){
    questions.push({
      type: 'mcq',
      q: 'أي من هذه المصطلحات ذكرتها في شرحك؟',
      opts: keywords.slice(0,4).sort(()=>Math.random()-.5),
      idx: 0,
      exp: 'كل هذه من شرحك'
    });
  }

  // قص وخلط
  return questions.slice(0, total).sort(()=>Math.random()-.5);
}

// ============ عرض التحليل + توليد الأسئلة ============
$('btnFinish').addEventListener('click', startAnalysis);
$('textAnalyze').addEventListener('click', startAnalysis);

function startAnalysis(){
  if(S.transcript.trim().length < 30){
    toast('النص قصير جداً، اشرح أكثر','warn');
    return;
  }
  go('analyzeScreen');

  const steps = ['step1','step2','step3','step4'];
  let i = 0;
  steps.forEach(id=>$(id).classList.remove('active','done'));
  const stepInterval = setInterval(()=>{
    if(i>0) $(steps[i-1]).classList.remove('active');
    if(i>0) $(steps[i-1]).classList.add('done');
    if(i<steps.length){
      $(steps[i]).classList.add('active');
      i++;
    }else{
      clearInterval(stepInterval);
    }
  },600);

  setTimeout(()=>{
    const keywords = extractKeywords(S.transcript, 20);
    const sentences = extractInformativeSentences(S.transcript, 15);
    S.concepts = extractConcepts(keywords, sentences);
    S.questions = generateQuestions();

    // عرض البصمة الدراسية
    const words = S.transcript.trim().split(/\s+/).filter(w=>w.length>0);
    const chars = S.transcript.length;
    const sents = S.transcript.split(/[.!؟\n]/).filter(s=>s.trim().length>10);
    const uniqueWords = new Set(words.map(cleanWord).filter(w=>w.length>1)).size;

    $('analysisResult').innerHTML = L(
      '<div class="mod-card analysis-result" style="padding:24px;">',
        '<h2 style="margin-bottom:20px;">📊 بصمتك الدراسية</h2>',
        '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:12px;margin-bottom:24px;">',
          '<div style="background:var(--surface);padding:16px;border-radius:12px;text-align:center;border:1px solid var(--border-2)">',
            '<strong style="display:block;font-size:28px;color:var(--c)">'+words.length+'</strong>',
            '<small style="color:var(--text-2)">كلمة</small>',
          '</div>',
          '<div style="background:var(--surface);padding:16px;border-radius:12px;text-align:center;border:1px solid var(--border-2)">',
            '<strong style="display:block;font-size:28px;color:var(--c)">'+sents.length+'</strong>',
            '<small style="color:var(--text-2)">جملة</small>',
          '</div>',
          '<div style="background:var(--surface);padding:16px;border-radius:12px;text-align:center;border:1px solid var(--border-2)">',
            '<strong style="display:block;font-size:28px;color:var(--c)">'+keywords.length+'</strong>',
            '<small style="color:var(--text-2)">مفهوم</small>',
          '</div>',
          '<div style="background:var(--surface);padding:16px;border-radius:12px;text-align:center;border:1px solid var(--border-2)">',
            '<strong style="display:block;font-size:28px;color:var(--c)">'+S.questions.length+'</strong>',
            '<small style="color:var(--text-2)">سؤال جاهز</small>',
          '</div>',
        '</div>',
        '<div class="cluster"><h3>🔑 الكلمات المفتاحية</h3><div class="tags">',
          keywords.length ? keywords.map(k=>'<span class="tag">'+k+'</span>').join('') : '<span style="color:var(--text-2)">لا توجد كلمات كافية</span>',
        '</div></div>',
        '<div style="text-align:center;margin-top:20px;">',
          '<button class="btn-modern primary big-btn" id="goExam">🎯 ابدأ الامتحان الآن</button>',
        '</div>',
      '</div>'
    );
    $('goExam').addEventListener('click', startExam);
  }, 2500);
}

// ============ بدء الامتحان ============
function startExam(){
  if(!S.questions.length){
    toast('لا توجد أسئلة، أعد الشرح','warn');
    return;
  }
  S.exam = {
    idx:0,
    answers: new Array(S.questions.length).fill(null),
    timer:0,
    int: setInterval(()=>{
      S.exam.timer++;
      const m = String(Math.floor(S.exam.timer/60)).padStart(2,'0');
      const s = String(S.exam.timer%60).padStart(2,'0');
      $('timer').textContent = m+':'+s;
    },1000)
  };
  go('examScreen');
  renderQuestion();
}

function renderQuestion(){
  const q = S.questions[S.exam.idx];
  const total = S.questions.length;
  const typeMap = {'mcq':'خيارات', 'fill':'املأ الفراغ', 'tf':'صح أو خطأ', 'essay':'مقالي'};
  const typeLabel = typeMap[q.type] || '';

  $('questionCounter').textContent = 'سؤال '+(S.exam.idx+1)+' من '+total;
  $('progressFill').style.width = ((S.exam.idx+1)/total*100)+'%';
  $('btnPrev').disabled = S.exam.idx === 0;
  $('btnNext').textContent = S.exam.idx === total-1 ? 'إنهاء ✓' : 'التالي →';

  let html = '<span class="q-num">سؤال '+(S.exam.idx+1)+'</span> <span class="q-type">📚 '+typeLabel+'</span>';
  html += '<div class="q-text">'+q.q+'</div>';

  const answered = S.exam.answers[S.exam.idx] !== null;

  if(q.type === 'mcq'){
    html += '<div class="opts">';
    const letters = ['أ','ب','ج','د'];
    q.opts.forEach((o,i)=>{
      let cls = 'opt';
      if(answered){
        if(i === q.idx) cls += ' correct';
        else if(String(i) === S.exam.answers[S.exam.idx]) cls += ' wrong';
        else cls += '';
      }
      html += '<div class="'+cls+'" '+(!answered?'data-o="'+i+'" ':'')+'>';
      html += '<span class="opt-letter">'+(answered && i===q.idx?'✓':answered && String(i)===S.exam.answers[S.exam.idx]?'✗':letters[i])+'</span>';
      html += '<span>'+o+'</span></div>';
    });
    html += '</div>';
  } else if(q.type === 'fill'){
    if(answered){
      const ok = String(S.exam.answers[S.exam.idx]).trim() === q.ans.trim();
      html += '<input class="essay-input" value="'+S.exam.answers[S.exam.idx]+'" disabled style="border-color:'+(ok?'var(--suc)':'var(--dan)')+'">';
      if(!ok) html += '<div style="color:var(--suc);margin-top:8px">الإجابة الصحيحة: <strong>'+q.ans+'</strong></div>';
    }else{
      html += '<input class="essay-input" id="fillInput" placeholder="اكتب الكلمة التي تملأ الفراغ...">';
    }
  } else if(q.type === 'tf'){
    html += '<div class="opts">';
    if(answered){
      const user = S.exam.answers[S.exam.idx] === 'true';
      const cor = q.ans;
      html += '<div class="opt '+(cor?'correct':'')+'"><span class="opt-letter">'+(cor?'✓':'✗')+'</span><span>صحيح</span></div>';
      html += '<div class="opt '+(user===cor?'':'wrong')+'"><span class="opt-letter">'+(user===cor?'✓':'✗')+'</span><span>خطأ</span></div>';
    } else {
      html += '<div class="opt" data-tf="true"><span class="opt-letter">ص</span><span>صحيح</span></div>';
      html += '<div class="opt" data-tf="false"><span class="opt-letter">خ</span><span>خطأ</span></div>';
    }
    html += '</div>';
  } else if(q.type === 'essay'){
    html += '<textarea class="essay-input" id="essayInput" placeholder="اشرح بكلماتك الخاصة..." '+ (answered?'disabled':'')+'>'+ (answered||'')+'</textarea>';
  }

  $('questionCard').innerHTML = html;

  if(!answered){
    if(q.type === 'mcq'){
      document.querySelectorAll('[data-o]').forEach(el=>{
        el.addEventListener('click',()=>{
          S.exam.answers[S.exam.idx] = el.dataset.o;
          renderQuestion();
        });
      });
    } else if(q.type === 'tf'){
      document.querySelectorAll('[data-tf]').forEach(el=>{
        el.addEventListener('click',()=>{
          S.exam.answers[S.exam.idx] = el.dataset.tf;
          renderQuestion();
        });
      });
    } else if(q.type === 'fill'){
      const inp = $('fillInput');
      if(inp){
        inp.addEventListener('keydown',e=>{
          if(e.key==='Enter'){
            S.exam.answers[S.exam.idx] = inp.value;
            renderQuestion();
          }
        });
        inp.focus();
      }
    } else if(q.type === 'essay'){
      const inp = $('essayInput');
      if(inp){
        inp.focus();
      }
    }
  }
}

$('btnPrev').addEventListener('click',()=>{
  saveEssayText();
  if(S.exam.idx>0){S.exam.idx--;renderQuestion();}
});
$('btnNext').addEventListener('click',()=>{
  saveEssayText();
  const q = S.questions[S.exam.idx];
  const ans = S.exam.answers[S.exam.idx];
  if(ans === null && q.type !== 'essay'){
    toast('اختر إجابة أولاً','warn');
    return;
  }
  if(q.type === 'essay' && (!ans || ans.trim().length < 5)){
    if(!confirm('إجابتك قصيرة جداً. متابعة؟')) return;
  }
  if(S.exam.idx < S.questions.length-1){
    S.exam.idx++;renderQuestion();
  } else {
    finishExam();
  }
});

function saveEssayText(){
  const q = S.questions[S.exam.idx];
  const inp = $('essayInput');
  if(q && q.type==='essay' && inp && inp.value){
    S.exam.answers[S.exam.idx] = inp.value;
  }
}

// ============ إنهاء الامتحان وتقييم المقالي ============
function evaluateEssay(userAns, ref){
  if(!userAns || !ref) return 0;
  const u = userAns.toLowerCase();
  const r = ref.toLowerCase();
  const rWords = r.split(/\s+/).filter(w=>w.length>=3);
  let hits = 0;
  rWords.forEach(w => { if(u.includes(w.toLowerCase())) hits++; });
  const ratio = hits / Math.max(rWords.length,1);
  // مع scoring: 50% + نسبة hit
  if(u.includes(r)) return 100;
  if(ratio >= 0.5) return 75;
  if(ratio >= 0.25) return 50;
  if(ratio > 0 || userAns.length > 20) return 25;
  return 0;
}

function finishExam(){
  clearInterval(S.exam.int);
  saveEssayText();
  const {questions, answers, timer} = S.exam;
  let correct = 0;
  questions.forEach((q,i)=>{
    const a = answers[i];
    if(a === null || a === undefined) return;
    if(q.type === 'mcq'){
      if(String(a) === String(q.idx)) correct++;
    } else if(q.type === 'tf'){
      if(String(a) === String(q.ans)) correct++;
    } else if(q.type === 'fill'){
      if(String(a).trim() === String(q.ans).trim()) correct++;
    } else if(q.type === 'essay'){
      const score = evaluateEssay(a, q.ref);
      if(score >= 75) correct++;
      else if(score >= 50) correct += 0.5;
    }
  });
  const pct = Math.round((correct/questions.length)*100);

  let icon='🎉',title='ممتاز!',msg='إجابات رائعة - أنت فاهم المادة فعلياً.';
  if(pct<80){icon='👍';title='جيد';msg='فهمك متوسط - حاول تعيد النظر.';}
  if(pct<50){icon='💪';title='يحتاج مراجعة';msg='استمع لشرحك وأعد المحاولة.';}
  $('resultIcon').textContent = icon;
  $('resultTitle').textContent = title;
  $('resultMsg').textContent = msg;
  $('scoreNum').textContent = pct;
  $('correctNum').textContent = Math.round(correct);
  $('totalNum').textContent = questions.length;
  const mm=String(Math.floor(timer/60)).padStart(2,'0');
  const ss=String(timer%60).padStart(2,'0');
  $('timeSpent').textContent = mm+':'+ss;
  setTimeout(()=>{
    $('scoreCircle').style.strokeDashoffset = 326.7 - (pct/100)*326.7;
  },100);
  if(pct >= 60){
    const c = $('confetti');
    c.innerHTML = '';
    const cols = ['#7c3aed','#06b6d4','#f59e0b','#10b981','#ec4899'];
    for(let i=0;i< (pct===100?80:30); i++){
      const el = document.createElement('i');
      el.style.left = Math.random()*100+'%';
      el.style.background = cols[Math.floor(Math.random()*cols.length)];
      el.style.animationDelay = Math.random()*2+'s';
      el.style.animationDuration = (2+Math.random()*2)+'s';
      c.appendChild(el);
    }
  }
  go('resultScreen');
}

// ============ المراجعة ============
function showReview(){
  const {questions, answers} = S.exam;
  $('reviewContent').innerHTML = questions.map((q,i)=>{
    let ok = false;
    let ua = '', ca = '';
    if(q.type === 'mcq'){
      ua = answers[i] !== null ? q.opts[answers[i]] : 'لم تُجب';
      ca = q.opts[q.idx];
      ok = String(answers[i]) === String(q.idx);
    } else if(q.type === 'tf'){
      ua = answers[i] !== null ? (answers[i]==='true'?'صحيح':'خطأ') : 'لم تُجب';
      ca = q.ans ? 'صحيح' : 'خطأ';
      ok = String(answers[i]) === String(q.ans);
    } else if(q.type === 'fill'){
      ua = answers[i] || 'لم تُجب';
      ca = q.ans;
      ok = String(answers[i]).trim() === String(q.ans).trim();
    } else if(q.type === 'essay'){
      ua = answers[i] || 'لم تُجب';
      ca = q.refSent;
      const s = evaluateEssay(answers[i]||'', q.ref);
      ok = s >= 75;
    }
    return '<div class="review-item '+(ok?'r':'w')+'">'+
      '<h3>'+(i+1)+'. '+q.q+'</h3>'+
      '<div class="ya '+(ok?'r':'w')+'"><strong>إجابتك:</strong> '+ua+' '+(ok?'✅':'❌')+'</div>'+
      (!ok?'<div class="ya r"><strong>المتوقع:</strong> '+ca+'</div>':'')+
      '<div class="explain">💡 '+q.exp+'</div>'+
    '</div>';
  }).join('');
  go('reviewScreen');
}

$('btnReview').addEventListener('click', showReview);
$('backToResult').addEventListener('click',()=>go('resultScreen'));
$('btnRetake').addEventListener('click', startExam);

// ============ Init ============
document.addEventListener('DOMContentLoaded',()=>{
  if(!('webkitSpeechRecognition' in window) && !('SpeechRecognition' in window)){
    toast('تنبيه: متصفحك لا يدعم التعرف على الصوت، استخدم الكتابة','warn');
  }
});

:root{
  --bg:#0a0a1a;--bg-2:#12122a;--bg-3:#1a1a35;
  --surface:rgba(255,255,255,.04);--surface-2:rgba(255,255,255,.07);
  --border:rgba(255,255,255,.08);--border-2:rgba(255,255,255,.14);
  --text:#f1f1fa;--text-2:#9b9bb8;--text-3:#5d5d7a;
  --p:#7c3aed;--p-2:#a78bfa;--c:#06b6d4;
  --suc:#10b981;--dan:#ef4444;--warn:#f59e0b;
  --grad:linear-gradient(135deg,#7c3aed,#06b6d4);
  --grad-w:linear-gradient(135deg,#f59e0b,#ef4444);
  --grad-s:linear-gradient(135deg,#10b981,#06b6d4);
  --shadow:0 20px 60px rgba(0,0,0,.5);
  --glow:0 0 40px rgba(124,58,237,.4);
  --r:20px;--r-sm:12px;
}
[data-theme="light"]{
  --bg:#f8f7fc;--bg-2:#fff;--bg-3:#f1eef9;
  --surface:rgba(255,255,255,.7);--surface-2:rgba(255,255,255,.9);
  --border:rgba(124,58,237,.1);--border-2:rgba(124,58,237,.2);
  --text:#1a1a2e;--text-2:#5d5d7a;
}
*{box-sizing:border-box;margin:0;padding:0;}
html,body{min-height:100%;font-family:'Cairo','Segoe UI','Tajawal',sans-serif;}
body{background:var(--bg);color:var(--text);line-height:1.7;overflow-x:hidden;
  background-image:radial-gradient(at 20% 0%,rgba(124,58,237,.15) 0%,transparent 50%),
                   radial-gradient(at 80% 100%,rgba(6,182,212,.1) 0%,transparent 50%);}
.container{max-width:1100px;margin:0 auto;padding:24px 20px;}

.aurora{position:fixed;inset:0;z-index:-1;overflow:hidden;pointer-events:none;}
.orb{position:absolute;border-radius:50%;filter:blur(80px);opacity:.4;mix-blend-mode:screen;}
.o1{width:500px;height:500px;background:#7c3aed;top:-100px;right:-100px;animation:f1 20s infinite;}
.o2{width:400px;height:400px;background:#06b6d4;bottom:-50px;left:-100px;animation:f2 25s infinite;}
.o3{width:300px;height:300px;background:#ec4899;top:50%;left:50%;animation:f3 18s infinite;}
@keyframes f1{0%,100%{transform:translate(0,0)}50%{transform:translate(-100px,100px)}}
@keyframes f2{0%,100%{transform:translate(0,0)}50%{transform:translate(80px,-80px)}}
@keyframes f3{0%,100%{transform:translate(-50%,-50%)}50%{transform:translate(-30%,-70%)}}

.navbar{position:sticky;top:0;z-index:100;backdrop-filter:blur(20px);background:rgba(10,10,26,.7);border-bottom:1px solid var(--border);}
.nav-inner{max-width:1100px;margin:0 auto;padding:14px 24px;display:flex;justify-content:space-between;align-items:center;}
.brand{display:flex;align-items:center;gap:10px;font-weight:bold;font-size:18px;}
.brand-icon{width:36px;height:36px;border-radius:10px;background:var(--grad);display:grid;place-items:center;color:white;font-size:18px;box-shadow:var(--glow);}
.theme-btn{width:36px;height:36px;border:none;background:var(--surface);border:1px solid var(--border-2);border-radius:50%;cursor:pointer;font-size:16px;color:var(--text);transition:.2s;}
.theme-btn:hover{transform:rotate(30deg) scale(1.1);}

.screen{display:none;min-height:calc(100vh - 70px);animation:fadeUp .5s;}
.screen.active{display:block;}
@keyframes fadeUp{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}

/* Hero */
.hero-wrap{padding:60px 0;text-align:center;}
.hero-badge{display:inline-block;padding:6px 16px;background:var(--surface);border:1px solid var(--border-2);border-radius:100px;font-size:13px;margin-bottom:20px;}
.hero-title{font-size:clamp(32px,5vw,56px);font-weight:800;line-height:1.1;margin-bottom:16px;letter-spacing:-1px;}
.gradient-text{background:var(--grad);-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:transparent;}
.hero-sub{color:var(--text-2);font-size:17px;margin-bottom:32px;max-width:600px;margin-left:auto;margin-right:auto;}

/* Settings Card */
.settings-card{text-align:right;max-width:700px;margin:0 auto 30px;padding:28px;}
.setting-row{margin-bottom:20px;}
.setting-row label{display:block;font-size:14px;color:var(--text-2);margin-bottom:8px;}
.setting-row input[type="text"]{width:100%;padding:12px 16px;background:var(--surface);border:1px solid var(--border-2);border-radius:12px;color:var(--text);font-size:15px;font-family:inherit;transition:.2s;}
.setting-row input[type="text"]:focus{outline:none;border-color:var(--p);}
.chips{display:flex;gap:8px;flex-wrap:wrap;}
.chip{padding:8px 16px;border:1px solid var(--border-2);background:var(--surface);border-radius:100px;cursor:pointer;font-family:inherit;color:var(--text-2);font-size:13px;transition:.2s;}
.chip.active{background:var(--grad);color:white;border-color:transparent;}
.chip:hover:not(.active){transform:translateY(-2px);}

/* Buttons */
.btn-modern{padding:14px 28px;border:none;border-radius:14px;font-size:15px;font-weight:600;cursor:pointer;display:inline-flex;align-items:center;gap:10px;font-family:inherit;transition:all .25s;}
.btn-modern.primary{background:var(--grad);color:white;box-shadow:0 10px 30px rgba(124,58,237,.4);}
.btn-modern.primary:hover:not(:disabled){transform:translateY(-3px);box-shadow:0 15px 40px rgba(124,58,237,.6);}
.btn-modern.gradient{background:var(--grad-s);color:white;}
.btn-modern.ghost{background:var(--surface);color:var(--text);border:1px solid var(--border-2);}
.btn-modern.ghost:hover{background:var(--surface-2);transform:translateY(-2px);}
.btn-modern:disabled{opacity:.4;cursor:not-allowed;}
.big-btn{padding:18px 40px;font-size:18px;margin:10px;}
.big-btn .mic-icon{font-size:24px;animation:pulse 2s infinite;}
@keyframes pulse{0%,100%{transform:scale(1)}50%{transform:scale(1.1)}}

/* Page Header */
.page-header{display:grid;grid-template-columns:auto 1fr auto;align-items:center;gap:14px;padding:20px 0;}
.page-header h1{font-size:clamp(18px,4vw,28px);font-weight:700;text-align:center;}
.icon-btn{width:40px;height:40px;border:none;background:var(--surface);border:1px solid var(--border-2);border-radius:12px;cursor:pointer;color:var(--text);font-size:18px;transition:.2s;}
.icon-btn:hover{background:var(--surface-2);transform:scale(1.05);}

/* Modern Card */
.mod-card{background:var(--surface);backdrop-filter:blur(20px);border:1px solid var(--border-2);border-radius:var(--r);padding:24px;transition:.3s;}

/* Record Screen */
.record-wrap{max-width:900px;}
.rec-status{text-align:center;padding:40px 20px;margin-bottom:24px;position:relative;}
.pulse-ring{position:absolute;top:50%;left:50%;width:140px;height:140px;border-radius:50%;border:2px solid var(--p);transform:translate(-50%,-50%);opacity:0;animation:pulsing 2s infinite;}
.pulse-ring.active{opacity:1;}
@keyframes pulsing{0%{transform:translate(-50%,-50%) scale(.8);opacity:.8}100%{transform:translate(-50%,-50%) scale(1.5);opacity:0}}
.mic-main{width:120px;height:120px;border-radius:50%;background:var(--grad);border:none;cursor:pointer;box-shadow:var(--glow);position:relative;z-index:2;transition:.3s;}
.mic-main:hover{transform:scale(1.05);}
.mic-main.recording{background:var(--grad-w);animation:recPulse 1s infinite;}
@keyframes recPulse{0%,100%{box-shadow:0 0 0 0 rgba(239,68,68,.7)}50%{box-shadow:0 0 0 20px rgba(239,68,68,0)}}
.mic-icon-big{font-size:54px;}
.rec-info{margin-top:20px;}
.rec-status-text{font-size:18px;font-weight:600;margin-bottom:6px;}
.rec-timer{font-size:28px;font-weight:700;color:var(--warn);font-variant-numeric:tabular-nums;}

/* Transcript */
.transcript-box{padding:0;overflow:hidden;}
.transcript-header{display:flex;justify-content:space-between;align-items:center;padding:14px 20px;border-bottom:1px solid var(--border);background:var(--surface-2);font-size:14px;font-weight:600;}
.word-count{color:var(--text-2);font-weight:normal;font-size:13px;}
.transcript-text{padding:24px;min-height:200px;max-height:400px;overflow-y:auto;font-size:16px;line-height:1.9;text-align:right;}
.placeholder{color:var(--text-3);font-style:italic;}
.final{color:var(--text);}
.interim{color:var(--text-2);font-style:italic;}

.rec-actions{display:flex;gap:12px;justify-content:center;flex-wrap:wrap;margin-top:30px;}

/* Text Input */
.big-textarea{width:100%;min-height:400px;padding:24px;background:var(--surface);border:1px solid var(--border-2);border-radius:var(--r);color:var(--text);font-size:16px;font-family:inherit;line-height:1.9;resize:vertical;transition:.2s;}
.big-textarea:focus{outline:none;border-color:var(--p);}
.text-stats{display:flex;gap:24px;justify-content:center;margin:18px 0;color:var(--text-2);font-size:14px;}
.text-stats span strong{color:var(--p-2);font-weight:600;}

/* Analyze */
.analyze-card{padding:30px;margin-bottom:24px;}
.analyze-step{display:flex;align-items:center;gap:14px;padding:14px 18px;border-radius:12px;margin-bottom:10px;background:var(--surface);transition:.3s;border:1px solid var(--border);}
.analyze-step.active{background:linear-gradient(135deg,rgba(124,58,237,.15),rgba(6,182,212,.15));border-color:var(--p);transform:translateX(-6px);}
.analyze-step.done{background:rgba(16,185,129,.1);border-color:var(--suc);}
.analyze-step span:first-child{font-size:24px;}
.analyze-step.active span:last-child{animation:dotdot 1.5s infinite;}
@keyframes dotdot{0%,100%{opacity:1}50%{opacity:.5}}

.analysis-result{padding:0;}

.cluster{background:var(--surface);border:1px solid var(--border-2);border-radius:var(--r-sm);padding:18px;margin-bottom:14px;}
.cluster h3{font-size:15px;margin-bottom:12px;color:var(--p-2);display:flex;align-items:center;gap:8px;}
.cluster .tags{display:flex;flex-wrap:wrap;gap:6px;}
.tag{background:rgba(124,58,237,.18);color:var(--p-2);padding:5px 12px;border-radius:100px;font-size:13px;border:1px solid rgba(124,58,237,.3);}

/* Exam */
.exam-bar{display:flex;justify-content:space-between;align-items:center;padding:18px 22px;margin-bottom:20px;gap:14px;}
.exam-progress{flex:1;}
.prog-track{height:6px;background:rgba(255,255,255,.08);border-radius:3px;overflow:hidden;margin-top:8px;}
.prog-fill{height:100%;background:var(--grad);transition:width .3s;}
.exam-timer{font-size:18px;font-weight:700;color:var(--warn);font-variant-numeric:tabular-nums;}
.question-card{padding:32px;min-height:360px;}
.q-text{font-size:19px;font-weight:700;margin-bottom:24px;line-height:1.5;}
.q-num{display:inline-block;background:var(--grad);color:white;padding:2px 14px;border-radius:100px;font-size:13px;margin-bottom:10px;}
.q-type{font-size:12px;color:var(--text-2);margin-right:8px;}
.opts{display:flex;flex-direction:column;gap:10px;}
.opt{padding:14px 18px;background:rgba(255,255,255,.03);border:1.5px solid var(--border-2);border-radius:14px;cursor:pointer;transition:.25s;display:flex;align-items:center;gap:14px;font-size:15px;text-align:right;}
.opt:hover{border-color:var(--p);background:rgba(124,58,237,.08);transform:translateX(-4px);}
.opt.selected{border-color:var(--p);background:rgba(124,58,237,.15);}
.opt.correct{border-color:var(--suc);background:linear-gradient(135deg,rgba(16,185,129,.2),rgba(16,185,129,.1));}
.opt.wrong{border-color:var(--dan);background:linear-gradient(135deg,rgba(239,68,68,.2),rgba(239,68,68,.1));animation:shake .4s;}
.opt-letter{width:34px;height:34px;border-radius:50%;display:grid;place-items:center;font-weight:700;background:var(--surface);border:1px solid var(--border-2);font-size:14px;}
.opt.correct .opt-letter{background:var(--suc);border-color:var(--suc);color:white;}
.opt.wrong .opt-letter{background:var(--dan);border-color:var(--dan);color:white;}
@keyframes shake{0%,100%{transform:translateX(0)}25%{transform:translateX(-8px)}75%{transform:translateX(8px)}}
.essay-input{width:100%;min-height:120px;padding:14px;background:var(--surface);border:1px solid var(--border-2);border-radius:12px;color:var(--text);font-size:15px;font-family:inherit;resize:vertical;margin-top:12px;}
.essay-input:focus{outline:none;border-color:var(--p);}
.exam-nav{display:flex;justify-content:space-between;gap:12px;margin-top:24px;}

/* Result */
.result-card{padding:40px 32px;text-align:center;position:relative;overflow:hidden;}
.result-emoji{font-size:96px;margin-bottom:12px;animation:popIn .6s cubic-bezier(.34,1.56,.64,1);}
@keyframes popIn{0%{transform:scale(0);opacity:0}100%{transform:scale(1);opacity:1}}
.result-card h1{font-size:38px;margin-bottom:10px;background:var(--grad);-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:transparent;}
.result-card p{color:var(--text-2);margin-bottom:20px;}
.ring-wrap{position:relative;width:170px;height:170px;margin:16px auto 28px;}
.ring-svg{transform:rotate(-90deg);width:100%;height:100%;filter:drop-shadow(0 0 20px rgba(124,58,237,.5));}
.ring-bg{fill:none;stroke:rgba(255,255,255,.1);stroke-width:8;}
.ring-fg{fill:none;stroke:url(#ringGrad);stroke-width:8;stroke-linecap:round;stroke-dasharray:326.7;stroke-dashoffset:326.7;transition:stroke-dashoffset 1.5s cubic-bezier(.34,1.56,.64,1);}
.ring-text{position:absolute;inset:0;display:grid;place-items:center;font-size:46px;font-weight:800;}
.ring-text small{font-size:22px;color:var(--text-2);}
.result-stats{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:26px;}
.result-stats>div{background:rgba(255,255,255,.04);padding:14px;border-radius:12px;border:1px solid var(--border);}
.result-stats strong{display:block;font-size:24px;color:var(--p-2);}
.result-stats span{font-size:11px;color:var(--text-2);}
.result-actions{display:flex;gap:10px;justify-content:center;flex-wrap:wrap;}
.confetti{position:absolute;inset:0;pointer-events:none;overflow:hidden;}
.confetti i{position:absolute;width:8px;height:14px;top:-20px;animation:fall 3s linear forwards;}
@keyframes fall{to{transform:translateY(120vh) rotate(720deg);opacity:0}}

/* Review */
.review-item{background:var(--surface);backdrop-filter:blur(20px);border:1px solid var(--border-2);border-radius:var(--r);padding:22px;margin-bottom:14px;border-right:4px solid var(--border);}
.review-item.r{border-right-color:var(--suc);}
.review-item.w{border-right-color:var(--dan);}
.review-item h3{font-size:16px;margin-bottom:12px;}
.ya{margin:8px 0;padding:10px;border-radius:10px;background:rgba(255,255,255,.04);font-size:14px;}
.ya.r{background:rgba(16,185,129,.15);color:var(--suc);}
.ya.w{background:rgba(239,68,68,.15);color:var(--dan);}
.explain{background:rgba(124,58,237,.1);padding:10px;border-radius:10px;font-size:13px;color:var(--text-2);margin-top:10px;border-right:3px solid var(--p);}

.toast{position:fixed;bottom:30px;left:50%;transform:translateX(-50%) translateY(100px);background:var(--grad);color:white;padding:14px 24px;border-radius:14px;font-weight:600;z-index:200;transition:.4s cubic-bezier(.34,1.56,.64,1);box-shadow:0 20px 40px rgba(124,58,237,.4);}
.toast.show{transform:translateX(-50%) translateY(0);}
.toast.warn{background:var(--warn);}
.toast.err{background:var(--dan);}

@media(max-width:768px){
  .hero-wrap{padding:30px 0;}
  .result-stats{grid-template-columns:repeat(3,1fr);}
  .question-card{padding:22px;}
  .exam-bar{flex-direction:column;align-items:stretch;}
}

const http = require('http');
const fs = require('fs');
const path = require('path');

const PORT = 8080;
const ROOT = __dirname;

const types = {
  '.html': 'text/html; charset=utf-8',
  '.css': 'text/css; charset=utf-8',
  '.js': 'application/javascript; charset=utf-8',
  '.json': 'application/json',
  '.png': 'image/png', '.jpg':'image/jpeg', '.svg':'image/svg+xml'
};

http.createServer((req, res) => {
  let url = req.url.split('?')[0];
  if (url === '/') url = '/index.html';
  const fp = path.join(ROOT, url);
  fs.readFile(fp, (err, data) => {
    if (err) {
      res.writeHead(404, {'Content-Type':'text/html; charset=utf-8'});
      res.end('<h1>404</h1><p>Missing: '+url+'</p>');
      return;
    }
    const ext = path.extname(fp);
    res.writeHead(200, {
      'Content-Type': types[ext] || 'text/plain; charset=utf-8',
      'Cache-Control': 'no-cache'
    });
    res.end(data);
  });
}).listen(PORT, '0.0.0.0', () => {
  console.log('Server: http://localhost:'+PORT);
});

// ============ State ============
const S = {
  currentLesson:null,
  exam:{questions:[],answers:[],idx:0,timer:0,int:null},
  progress:JSON.parse(localStorage.getItem('mp')||'{}'),
  user:JSON.parse(localStorage.getItem('mu')||'{"xp":0,"streak":0,"lastDay":null,"ach":[]}')
};
const save=()=>{localStorage.setItem('mp',JSON.stringify(S.progress));localStorage.setItem('mu',JSON.stringify(S.user));};

// ============ Toasts & Sound ============
const audioCtx=new(window.AudioContext||window.webkitAudioContext)();
function beep(f=440,d=.1,v=.1,t='sine'){
  try{const o=audioCtx.createOscillator(),g=audioCtx.createGain();
  o.connect(g);g.connect(audioCtx.destination);o.frequency.value=f;
  o.type=t;g.gain.setValueAtTime(v,audioCtx.currentTime);
  g.gain.exponentialRampToValueAtTime(.001,audioCtx.currentTime+d);
  o.start();o.stop(audioCtx.currentTime+d);}catch(e){}
}
const sound={correct:()=>{beep(523,.1);setTimeout(()=>beep(784,.15),80);},wrong:()=>beep(200,.2,.15,'sawtooth'),click:()=>beep(800,.05,.05),finish:()=>{beep(523,.1);setTimeout(()=>beep(659,.1),120);setTimeout(()=>beep(784,.2),240);},unlock:()=>{beep(659,.1);setTimeout(()=>beep(880,.15),100);setTimeout(()=>beep(1047,.2),200);}};
function toast(msg,type=''){const t=document.getElementById('toast');t.textContent=msg;t.className='toast show '+type;setTimeout(()=>t.className='toast',2400);}

// ============ Theme ============
document.getElementById('themeToggle').addEventListener('click',()=>{
  const h=document.documentElement;const n=h.dataset.theme==='dark'?'light':'dark';
  h.dataset.theme=n;document.getElementById('themeIcon').textContent=n==='dark'?'🌙':'☀️';
  localStorage.setItem('theme',n);
});
if(localStorage.getItem('theme')){document.documentElement.dataset.theme=localStorage.getItem('theme');document.getElementById('themeIcon').textContent=localStorage.getItem('theme')==='dark'?'🌙':'☀️';}

// ============ Navigation ============
function go(id){
  if(S.exam.int&&id!=='examScreen'){clearInterval(S.exam.int);S.exam.int=null;}
  document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));
  document.getElementById(id).classList.add('active');
  window.scrollTo({top:0,behavior:'smooth'});
}
document.querySelectorAll('[data-go]').forEach(el=>el.addEventListener('click',()=>{sound.click();go(el.dataset.go);}));

// ============ Streak ============
function updateStreak(){
  const today=new Date().toDateString();
  if(S.user.lastDay!==today){
    const y=new Date();y.setDate(y.getDate()-1);
    if(S.user.lastDay===y.toDateString())S.user.streak++;
    else if(S.user.lastDay!==null)S.user.streak=1;
    else S.user.streak=1;
    S.user.lastDay=today;save();
  }
}

// ============ Achievements ============
const ACHS=[
  {id:'first',name:'البداية',desc:'أول درس',icon:'🎯',check:()=>Object.keys(S.progress).length>=1},
  {id:'three',name:'متعلم نشيط',desc:'3 دروس',icon:'📚',check:()=>Object.keys(S.progress).length>=3},
  {id:'all',name:'خبير',desc:'كل الدروس',icon:'🏆',check:()=>Object.keys(S.progress).length>=6},
  {id:'high',name:'ممتاز',desc:'نتيجة 100%',icon:'💯',check:()=>Object.values(S.progress).some(p=>p.best===100)},
  {id:'good',name:'جيد جداً',desc:'نتيجة 90%+',icon:'⭐',check:()=>Object.values(S.progress).some(p=>p.best>=90)},
  {id:'streak3',name:'منتظم',desc:'سلسلة 3 أيام',icon:'🔥',check:()=>S.user.streak>=3},
];
function checkAchievements(){
  const newAch=[];
  ACHS.forEach(a=>{if(!S.user.ach.includes(a.id)&&a.check()){S.user.ach.push(a.id);newAch.push(a);}});
  if(newAch.length){save();sound.unlock();showAchPop(newAch);}
}
function showAchPop(achs){
  const pop=document.getElementById('newAchievement');
  if(achs.length){pop.style.display='inline-flex';document.getElementById('newAchText').textContent='إنجاز جديد: '+achs[0].name+' '+achs[0].icon;}
}
function renderAch(){
  const grid=document.getElementById('achGrid');
  grid.innerHTML=ACHS.map(a=>{
    const u=S.user.ach.includes(a.id);
    return `<div class="ach ${u?'unlocked':'locked'}">
      <div class="ach-icon">${a.icon}</div>
      <div class="ach-name">${a.name}</div>
      <div class="ach-desc">${a.desc}</div>
    </div>`;
  }).join('');
}

// ============ Stats ============
function updateStats(){
  updateStreak();
  const done=Object.keys(S.progress).length;
  const exams=Object.values(S.progress).filter(p=>p.best!==undefined).length;
  const avg=exams?Math.round(Object.values(S.progress).reduce((a,p)=>a+(p.best||0),0)/exams):0;
  document.getElementById('completedCount').textContent=done;
  document.getElementById('avgScore').textContent=avg+'%';
  document.getElementById('totalExams').textContent=exams;
  document.getElementById('streakCount').textContent=S.user.streak;
  document.getElementById('homeStreak').textContent=S.user.streak;
  document.getElementById('xpCount').textContent=S.user.xp;
}

// ============ Lessons Grid ============
function renderLessons(filter='الكل'){
  let ls=LESSONS;
  if(filter!=='all'&&filter!=='الكل')ls=ls.filter(l=>l.difficulty===filter);
  const grid=document.getElementById('lessonsGrid');
  grid.innerHTML=ls.map(l=>{
    const d=S.progress[l.id];
    return `<div class="mod-card" data-id="${l.id}">
      <div class="lesson-tile">
        ${d?`<div class="badge-top">✓ ${d.best||0}%</div>`:''}
        <div class="lesson-icon" style="background:${l.color}22;color:${l.color};">${l.icon}</div>
        <h3>${l.title}</h3>
        <p>${l.description}</p>
        <span class="diff diff-${l.difficulty}">${l.difficulty}</span>
        <div class="arrow">←</div>
      </div>
    </div>`;
  }).join('');
  grid.querySelectorAll('.mod-card').forEach(c=>c.addEventListener('click',()=>{sound.click();openLesson(c.dataset.id);}));
}

document.querySelectorAll('.filter-chip').forEach(b=>b.addEventListener('click',()=>{
  document.querySelectorAll('.filter-chip').forEach(x=>x.classList.remove('active'));
  b.classList.add('active');sound.click();renderLessons(b.dataset.filter);
}));

// ============ Lesson Page ============
function openLesson(id){
  const l=LESSONS.find(x=>x.id===id);S.currentLesson=l;
  document.getElementById('lessonTitle').textContent=l.title;
  document.getElementById('lessonContent').innerHTML=l.content;
  const m=document.getElementById('markDone');
  m.textContent=S.progress[id]?'✓':'✓';m.style.color=S.progress[id]?'var(--suc)':'';
  m.onclick=()=>{if(!S.progress[id]){S.progress[id]={best:0,completed:true};save();updateStats();toast('تم标记 الدرس كمكتمل ✓');}else toast('الدرس مكتمل مسبقاً','warn');};
  go('lessonScreen');
}

// ============ Start Exam ============
function startExam(){
  const l=S.currentLesson;
  const qs=[...l.exam].sort(()=>Math.random()-.5).slice(0,Math.min(6,l.exam.length));
  S.exam={questions:qs,answers:new Array(qs.length).fill(null),idx:0,timer:0,
    int:setInterval(()=>{S.exam.timer++;const m=String(Math.floor(S.exam.timer/60)).padStart(2,'0');const s=String(S.exam.timer%60).padStart(2,'0');document.getElementById('timer').textContent=`${m}:${s}`;},1000)};
  go('examScreen');renderQ();
}

// ============ Render Question ============
function renderQ(){
  const {questions,idx,answers}=S.exam;
  const q=questions[idx];const total=questions.length;
  document.getElementById('questionCounter').textContent=`سؤال ${idx+1} من ${total}`;
  document.getElementById('progressFill').style.width=`${((idx+1)/total)*100}%`;
  document.getElementById('btnPrev').disabled=idx===0;
  document.getElementById('btnNext').textContent=idx===total-1?'إنهاء ✓':'التالي →';
  const letters=['أ','ب','ج','د','هـ'];
  let h=`<span class="q-num">سؤال ${idx+1}</span><div class="q-text">${q.q}</div><div class="opts">`;
  if(q.type==='mcq'){
    q.options.forEach((o,i)=>{
      if(answers[idx]!==null){
        if(i===q.answer)h+=`<div class="opt correct"><span class="opt-letter">✓</span><span>${o}</span></div>`;
        else if(i===answers[idx])h+=`<div class="opt wrong"><span class="opt-letter">✗</span><span>${o}</span></div>`;
        else h+=`<div class="opt" style="opacity:.5"><span class="opt-letter">${letters[i]}</span><span>${o}</span></div>`;
      }else h+=`<div class="opt" data-o="${i}"><span class="opt-letter">${letters[i]}</span><span>${o}</span></div>`;
    });
  }else{
    const chk=answers[idx]!==null;
    [['صحيح',true],['خطأ',false]].forEach(([lbl,v])=>{
      if(chk){
        if(v===q.answer)h+=`<div class="opt correct"><span class="opt-letter">✓</span><span>${lbl}</span></div>`;
        else if(v===answers[idx])h+=`<div class="opt wrong"><span class="opt-letter">✗</span><span>${lbl}</span></div>`;
        else h+=`<div class="opt" style="opacity:.5"><span class="opt-letter">•</span><span>${lbl}</span></div>`;
      }else h+=`<div class="opt" data-tf="${v}"><span class="opt-letter">${lbl.charAt(0)}</span><span>${lbl}</span></div>`;
    });
  }
  h+='</div>';document.getElementById('questionCard').innerHTML=h;
  if(answers[idx]===null){
    document.querySelectorAll('[data-o]').forEach(el=>el.addEventListener('click',()=>{S.exam.answers[idx]=parseInt(el.dataset.o);sound.click();renderQ();}));
    document.querySelectorAll('[data-tf]').forEach(el=>el.addEventListener('click',()=>{S.exam.answers[idx]=el.dataset.tf==='true';const ok=S.exam.answers[idx]===q.answer;ok?(sound.correct()):sound.wrong();renderQ();}));
  }else{
    const ok=answers[idx]===q.answer;if(ok)sound.correct();else sound.wrong();
  }
}

document.getElementById('btnPrev').addEventListener('click',()=>{if(S.exam.idx>0){S.exam.idx--;renderQ();}});
document.getElementById('btnNext').addEventListener('click',()=>{
  const{idx,answers,questions}=S.exam;
  if(answers[idx]===null){toast('اختر إجابة أولاً','warn');return;}
  if(idx<questions.length-1){S.exam.idx++;renderQ();}else finishExam();
});

// ============ Finish Exam ============
function finishExam(){
  clearInterval(S.exam.int);
  const{questions,answers,timer}=S.exam;
  let correct=0;questions.forEach((q,i)=>{if(answers[i]===q.answer)correct++;});
  const pct=Math.round((correct/questions.length)*100);
  const xp=correct*10+(pct===100?50:pct>=80?25:pct>=50?10:0);
  S.user.xp+=xp;save();
  const lid=S.currentLesson.id;
  if(!S.progress[lid])S.progress[lid]={};
  S.progress[lid].best=Math.max(pct,S.progress[lid].best||0);
  S.progress[lid].last=pct;S.progress[lid].completed=true;
  save();updateStats();
  // Result UI
  let icon='🎉',title='ممتاز!',msg='أداء رائع، أنت فاهم المادة.';
  if(pct<80){icon='👍';title='جيد، استمر!';msg='مستوى جيد لكن في مجال للتحسن.';}
  if(pct<50){icon='💪';title='تحتاج مراجعة';msg='أعد قراءة الدرس والمحاولة مرة أخرى.';}
  document.getElementById('resultIcon').textContent=icon;
  document.getElementById('resultTitle').textContent=title;
  document.getElementById('resultMsg').textContent=msg;
  document.getElementById('scoreNum').textContent=pct;
  document.getElementById('correctNum').textContent=correct;
  document.getElementById('totalNum').textContent=questions.length;
  document.getElementById('earnedXp').textContent='+'+xp;
  const mm=String(Math.floor(timer/60)).padStart(2,'0');const ss=String(timer%60).padStart(2,'0');
  document.getElementById('timeSpent').textContent=`${mm}:${ss}`;
  // Ring
  setTimeout(()=>{
    const off=326.7-(pct/100)*326.7;
    const c=document.getElementById('scoreCircle');c.style.strokeDashoffset=off;
  },100);
  // Confetti & sound
  if(pct>=50){sound.finish();if(pct===100)confetti();else if(pct>=80)lightConfetti();}
  document.getElementById('newAchievement').style.display='none';
  checkAchievements();
  go('resultScreen');
}

function confetti(){const c=document.getElementById('confetti');c.innerHTML='';const cols=['#7c3aed','#06b6d4','#f59e0b','#10b981','#ec4899','#ef4444'];
  for(let i=0;i<60;i++){const el=document.createElement('i');el.style.left=Math.random()*100+'%';el.style.background=cols[Math.floor(Math.random()*cols.length)];el.style.animationDelay=Math.random()*2+'s';el.style.animationDuration=(2+Math.random()*2)+'s';c.appendChild(el);}}
function lightConfetti(){const c=document.getElementById('confetti');c.innerHTML='';const cols=['#7c3aed','#06b6d4','#f59e0b'];
  for(let i=0;i<25;i++){const el=document.createElement('i');el.style.left=Math.random()*100+'%';el.style.background=cols[Math.floor(Math.random()*cols.length)];el.style.animationDelay=Math.random()*1+'s';el.style.animationDuration=(2+Math.random()*2)+'s';c.appendChild(el);}}

// ============ Review ============
function showReview(){
  const{questions,answers}=S.exam;
  document.getElementById('reviewContent').innerHTML=questions.map((q,i)=>{
    const ok=answers[i]===q.answer;
    let ua,ca;
    if(q.type==='mcq'){ua=answers[i]!==null?q.options[answers[i]]:'لم يُجب';ca=q.options[q.answer];}
    else{ua=answers[i]!==null?(answers[i]?'صحيح':'خطأ'):'لم يُجب';ca=q.answer?'صحيح':'خطأ';}
    return `<div class="review-item ${ok?'r':'w'}">
      <h3>${i+1}. ${q.q}</h3>
      <div class="ya ${ok?'ya-r':'ya-w'}"><strong>إجابتك:</strong> ${ua} ${ok?'✅':'❌'}</div>
      ${!ok?`<div class="ya ya-r"><strong>الصحيحة:</strong> ${ca}</div>`:''}
      <div class="explain">💡 ${q.exp}</div>
    </div>`;
  }).join('');
  go('reviewScreen');
}
document.getElementById('btnReview').addEventListener('click',showReview);
document.getElementById('backToResult').addEventListener('click',()=>go('resultScreen'));
document.getElementById('btnRetake').addEventListener('click',startExam);
document.getElementById('startBtn').addEventListener('click',()=>{renderLessons();go('lessonsScreen');});
document.getElementById('btnReRead').addEventListener('click',()=>window.scrollTo({top:0,behavior:'smooth'}));
document.getElementById('btnStartExam').addEventListener('click',startExam);

