}
[data-theme="light"]{
  --bg:#f8f7fc;--bg-2:#ffffff;--bg-3:#f1eef9;
  --surface:rgba(255,255,255,.7);--surface-2:rgba(255,255,255,.9);
  --border:rgba(124,58,237,.1);--border-2:rgba(124,58,237,.2);
  --text:#1a1a2e;--text-2:#5d5d7a;--text-3:#9b9bb8;
  --shadow:0 20px 60px rgba(124,58,237,.15);
}

*{box-sizing:border-box;margin:0;padding:0;}
html,body{min-height:100%;}
body{
  font-family:'Cairo','Segoe UI','Tajawal',sans-serif;
  background:var(--bg);color:var(--text);line-height:1.7;
  overflow-x:hidden;
  background-image:radial-gradient(at 20% 0%,rgba(124,58,237,.15) 0%,transparent 50%),
                   radial-gradient(at 80% 100%,rgba(6,182,212,.1) 0%,transparent 50%);
}
.container{max-width:1200px;margin:0 auto;padding:24px 20px;}

/* ============ Aurora Background ============ */
.aurora{position:fixed;inset:0;z-index:-1;overflow:hidden;pointer-events:none;}
.orb{position:absolute;border-radius:50%;filter:blur(80px);opacity:.4;mix-blend-mode:screen;}
.o1{width:500px;height:500px;background:#7c3aed;top:-100px;right:-100px;animation:float1 20s infinite;}
.o2{width:400px;height:400px;background:#06b6d4;bottom:-50px;left:-100px;animation:float2 25s infinite;}
