:root{
  --bg:#0a0a1a;--bg-2:#12122a;--bg-3:#1a1a35;
  --surface:rgba(255,255,255,.04);--surface-2:rgba(255,255,255,.07);
  --border:rgba(255,255,255,.08);--border-2:rgba(255,255,255,.14);
  --text:#f1f1fa;--text-2:#9b9bb8;--text-3:#5d5d7a;
  --p:#7c3aed;--p-2:#a78bfa;--c:#06b6d4;
  --suc:#10b981;--dan:#ef4444;--warn:#f59e0b;
  --grad:linear-gradient(135deg,#7c3aed,#06b6d4);
  --grad-w:linear-gradient(135deg,#f59e0b,#ef4444);
  --grad-s:linear-gradient(135deg,#10b981,#06b6d4);
  --shadow:0 20px 60px rgba(0,0,0,.5);
  --glow:0 0 40px rgba(124,58,237,.4);
  --r:20px;--r-sm:12px;
}
[data-theme="light"]{
  --bg:#f8f7fc;--bg-2:#fff;--bg-3:#f1eef9;
  --surface:rgba(255,255,255,.7);--surface-2:rgba(255,255,255,.9);
  --border:rgba(124,58,237,.1);--border-2:rgba(124,58,237,.2);
  --text:#1a1a2e;--text-2:#5d5d7a;
}
*{box-sizing:border-box;margin:0;padding:0;}
html,body{min-height:100%;font-family:'Cairo','Segoe UI','Tajawal',sans-serif;}
body{background:var(--bg);color:var(--text);line-height:1.7;overflow-x:hidden;
  background-image:radial-gradient(at 20% 0%,rgba(124,58,237,.15) 0%,transparent 50%),
                   radial-gradient(at 80% 100%,rgba(6,182,212,.1) 0%,transparent 50%);}
.container{max-width:1100px;margin:0 auto;padding:24px 20px;}

.aurora{position:fixed;inset:0;z-index:-1;overflow:hidden;pointer-events:none;}
.orb{position:absolute;border-radius:50%;filter:blur(80px);opacity:.4;mix-blend-mode:screen;}
.o1{width:500px;height:500px;background:#7c3aed;top:-100px;right:-100px;animation:f1 20s infinite;}
.o2{width:400px;height:400px;background:#06b6d4;bottom:-50px;left:-100px;animation:f2 25s infinite;}
.o3{width:300px;height:300px;background:#ec4899;top:50%;left:50%;animation:f3 18s infinite;}
@keyframes f1{0%,100%{transform:translate(0,0)}50%{transform:translate(-100px,100px)}}
@keyframes f2{0%,100%{transform:translate(0,0)}50%{transform:translate(80px,-80px)}}
@keyframes f3{0%,100%{transform:translate(-50%,-50%)}50%{transform:translate(-30%,-70%)}}

.navbar{position:sticky;top:0;z-index:100;backdrop-filter:blur(20px);background:rgba(10,10,26,.7);border-bottom:1px solid var(--border);}
.nav-inner{max-width:1100px;margin:0 auto;padding:14px 24px;display:flex;justify-content:space-between;align-items:center;}
.brand{display:flex;align-items:center;gap:10px;font-weight:bold;font-size:18px;}
.brand-icon{width:36px;height:36px;border-radius:10px;background:var(--grad);display:grid;place-items:center;color:white;font-size:18px;box-shadow:var(--glow);}
.theme-btn{width:36px;height:36px;border:none;background:var(--surface);border:1px solid var(--border-2);border-radius:50%;cursor:pointer;font-size:16px;color:var(--text);transition:.2s;}
.theme-btn:hover{transform:rotate(30deg) scale(1.1);}

.screen{display:none;min-height:calc(100vh - 70px);animation:fadeUp .5s;}
.screen.active{display:block;}
@keyframes fadeUp{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}

/* Hero */
.hero-wrap{padding:60px 0;text-align:center;}
.hero-badge{display:inline-block;padding:6px 16px;background:var(--surface);border:1px solid var(--border-2);border-radius:100px;font-size:13px;margin-bottom:20px;}
.hero-title{font-size:clamp(32px,5vw,56px);font-weight:800;line-height:1.1;margin-bottom:16px;letter-spacing:-1px;}
.gradient-text{background:var(--grad);-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:transparent;}
.hero-sub{color:var(--text-2);font-size:17px;margin-bottom:32px;max-width:600px;margin-left:auto;margin-right:auto;}

/* Settings Card */
.settings-card{text-align:right;max-width:700px;margin:0 auto 30px;padding:28px;}
.setting-row{margin-bottom:20px;}
.setting-row label{display:block;font-size:14px;color:var(--text-2);margin-bottom:8px;}
.setting-row input[type="text"]{width:100%;padding:12px 16px;background:var(--surface);border:1px solid var(--border-2);border-radius:12px;color:var(--text);font-size:15px;font-family:inherit;transition:.2s;}
.setting-row input[type="text"]:focus{outline:none;border-color:var(--p);}
.chips{display:flex;gap:8px;flex-wrap:wrap;}
.chip{padding:8px 16px;border:1px solid var(--border-2);background:var(--surface);border-radius:100px;cursor:pointer;font-family:inherit;color:var(--text-2);font-size:13px;transition:.2s;}
.chip.active{background:var(--grad);color:white;border-color:transparent;}
.chip:hover:not(.active){transform:translateY(-2px);}

/* Buttons */
.btn-modern{padding:14px 28px;border:none;border-radius:14px;font-size:15px;font-weight:600;cursor:pointer;display:inline-flex;align-items:center;gap:10px;font-family:inherit;transition:all .25s;}
.btn-modern.primary{background:var(--grad);color:white;box-shadow:0 10px 30px rgba(124,58,237,.4);}
.btn-modern.primary:hover:not(:disabled){transform:translateY(-3px);box-shadow:0 15px 40px rgba(124,58,237,.6);}
.btn-modern.gradient{background:var(--grad-s);color:white;}
.btn-modern.ghost{background:var(--surface);color:var(--text);border:1px solid var(--border-2);}
.btn-modern.ghost:hover{background:var(--surface-2);transform:translateY(-2px);}
.btn-modern:disabled{opacity:.4;cursor:not-allowed;}
.big-btn{padding:18px 40px;font-size:18px;margin:10px;}
.big-btn .mic-icon{font-size:24px;animation:pulse 2s infinite;}
@keyframes pulse{0%,100%{transform:scale(1)}50%{transform:scale(1.1)}}

/* Page Header */
.page-header{display:grid;grid-template-columns:auto 1fr auto;align-items:center;gap:14px;padding:20px 0;}
.page-header h1{font-size:clamp(18px,4vw,28px);font-weight:700;text-align:center;}
.icon-btn{width:40px;height:40px;border:none;background:var(--surface);border:1px solid var(--border-2);border-radius:12px;cursor:pointer;color:var(--text);font-size:18px;transition:.2s;}
.icon-btn:hover{background:var(--surface-2);transform:scale(1.05);}

/* Modern Card */
.mod-card{background:var(--surface);backdrop-filter:blur(20px);border:1px solid var(--border-2);border-radius:var(--r);padding:24px;transition:.3s;}

/* Record Screen */
.record-wrap{max-width:900px;}
.rec-status{text-align:center;padding:40px 20px;margin-bottom:24px;position:relative;}
.pulse-ring{position:absolute;top:50%;left:50%;width:140px;height:140px;border-radius:50%;border:2px solid var(--p);transform:translate(-50%,-50%);opacity:0;animation:pulsing 2s infinite;}
.pulse-ring.active{opacity:1;}
@keyframes pulsing{0%{transform:translate(-50%,-50%) scale(.8);opacity:.8}100%{transform:translate(-50%,-50%) scale(1.5);opacity:0}}
.mic-main{width:120px;height:120px;border-radius:50%;background:var(--grad);border:none;cursor:pointer;box-shadow:var(--glow);position:relative;z-index:2;transition:.3s;}
.mic-main:hover{transform:scale(1.05);}
.mic-main.recording{background:var(--grad-w);animation:recPulse 1s infinite;}
@keyframes recPulse{0%,100%{box-shadow:0 0 0 0 rgba(239,68,68,.7)}50%{box-shadow:0 0 0 20px rgba(239,68,68,0)}}
.mic-icon-big{font-size:54px;}
.rec-info{margin-top:20px;}
.rec-status-text{font-size:18px;font-weight:600;margin-bottom:6px;}
.rec-timer{font-size:28px;font-weight:700;color:var(--warn);font-variant-numeric:tabular-nums;}

/* Transcript */
.transcript-box{padding:0;overflow:hidden;}
.transcript-header{display:flex;justify-content:space-between;align-items:center;padding:14px 20px;border-bottom:1px solid var(--border);background:var(--surface-2);font-size:14px;font-weight:600;}
.word-count{color:var(--text-2);font-weight:normal;font-size:13px;}
.transcript-text{padding:24px;min-height:200px;max-height:400px;overflow-y:auto;font-size:16px;line-height:1.9;text-align:right;}
.placeholder{color:var(--text-3);font-style:italic;}
.final{color:var(--text);}
.interim{color:var(--text-2);font-style:italic;}

.rec-actions{display:flex;gap:12px;justify-content:center;flex-wrap:wrap;margin-top:30px;}

/* Text Input */
.big-textarea{width:100%;min-height:400px;padding:24px;background:var(--surface);border:1px solid var(--border-2);border-radius:var(--r);color:var(--text);font-size:16px;font-family:inherit;line-height:1.9;resize:vertical;transition:.2s;}
.big-textarea:focus{outline:none;border-color:var(--p);}
.text-stats{display:flex;gap:24px;justify-content:center;margin:18px 0;color:var(--text-2);font-size:14px;}
.text-stats span strong{color:var(--p-2);font-weight:600;}

/* Analyze */
.analyze-card{padding:30px;margin-bottom:24px;}
.analyze-step{display:flex;align-items:center;gap:14px;padding:14px 18px;border-radius:12px;margin-bottom:10px;background:var(--surface);transition:.3s;border:1px solid var(--border);}
.analyze-step.active{background:linear-gradient(135deg,rgba(124,58,237,.15),rgba(6,182,212,.15));border-color:var(--p);transform:translateX(-6px);}
.analyze-step.done{background:rgba(16,185,129,.1);border-color:var(--suc);}
.analyze-step span:first-child{font-size:24px;}
.analyze-step.active span:last-child{animation:dotdot 1.5s infinite;}
@keyframes dotdot{0%,100%{opacity:1}50%{opacity:.5}}

.analysis-result{padding:0;}

.cluster{background:var(--surface);border:1px solid var(--border-2);border-radius:var(--r-sm);padding:18px;margin-bottom:14px;}
.cluster h3{font-size:15px;margin-bottom:12px;color:var(--p-2);display:flex;align-items:center;gap:8px;}
.cluster .tags{display:flex;flex-wrap:wrap;gap:6px;}
.tag{background:rgba(124,58,237,.18);color:var(--p-2);padding:5px 12px;border-radius:100px;font-size:13px;border:1px solid rgba(124,58,237,.3);}

/* Exam */
.exam-bar{display:flex;justify-content:space-between;align-items:center;padding:18px 22px;margin-bottom:20px;gap:14px;}
.exam-progress{flex:1;}
.prog-track{height:6px;background:rgba(255,255,255,.08);border-radius:3px;overflow:hidden;margin-top:8px;}
.prog-fill{height:100%;background:var(--grad);transition:width .3s;}
.exam-timer{font-size:18px;font-weight:700;color:var(--warn);font-variant-numeric:tabular-nums;}
.question-card{padding:32px;min-height:360px;}
.q-text{font-size:19px;font-weight:700;margin-bottom:24px;line-height:1.5;}
.q-num{display:inline-block;background:var(--grad);color:white;padding:2px 14px;border-radius:100px;font-size:13px;margin-bottom:10px;}
.q-type{font-size:12px;color:var(--text-2);margin-right:8px;}
.opts{display:flex;flex-direction:column;gap:10px;}
.opt{padding:14px 18px;background:rgba(255,255,255,.03);border:1.5px solid var(--border-2);border-radius:14px;cursor:pointer;transition:.25s;display:flex;align-items:center;gap:14px;font-size:15px;text-align:right;}
.opt:hover{border-color:var(--p);background:rgba(124,58,237,.08);transform:translateX(-4px);}
.opt.selected{border-color:var(--p);background:rgba(124,58,237,.15);}
.opt.correct{border-color:var(--suc);background:linear-gradient(135deg,rgba(16,185,129,.2),rgba(16,185,129,.1));}
.opt.wrong{border-color:var(--dan);background:linear-gradient(135deg,rgba(239,68,68,.2),rgba(239,68,68,.1));animation:shake .4s;}
.opt-letter{width:34px;height:34px;border-radius:50%;display:grid;place-items:center;font-weight:700;background:var(--surface);border:1px solid var(--border-2);font-size:14px;}
.opt.correct .opt-letter{background:var(--suc);border-color:var(--suc);color:white;}
.opt.wrong .opt-letter{background:var(--dan);border-color:var(--dan);color:white;}
@keyframes shake{0%,100%{transform:translateX(0)}25%{transform:translateX(-8px)}75%{transform:translateX(8px)}}
.essay-input{width:100%;min-height:120px;padding:14px;background:var(--surface);border:1px solid var(--border-2);border-radius:12px;color:var(--text);font-size:15px;font-family:inherit;resize:vertical;margin-top:12px;}
.essay-input:focus{outline:none;border-color:var(--p);}
.exam-nav{display:flex;justify-content:space-between;gap:12px;margin-top:24px;}

/* Result */
.result-card{padding:40px 32px;text-align:center;position:relative;overflow:hidden;}
.result-emoji{font-size:96px;margin-bottom:12px;animation:popIn .6s cubic-bezier(.34,1.56,.64,1);}
@keyframes popIn{0%{transform:scale(0);opacity:0}100%{transform:scale(1);opacity:1}}
.result-card h1{font-size:38px;margin-bottom:10px;background:var(--grad);-webkit-background-clip:text;background-clip:text;-webkit-text-fill-color:transparent;}
.result-card p{color:var(--text-2);margin-bottom:20px;}
.ring-wrap{position:relative;width:170px;height:170px;margin:16px auto 28px;}
.ring-svg{transform:rotate(-90deg);width:100%;height:100%;filter:drop-shadow(0 0 20px rgba(124,58,237,.5));}
.ring-bg{fill:none;stroke:rgba(255,255,255,.1);stroke-width:8;}
.ring-fg{fill:none;stroke:url(#ringGrad);stroke-width:8;stroke-linecap:round;stroke-dasharray:326.7;stroke-dashoffset:326.7;transition:stroke-dashoffset 1.5s cubic-bezier(.34,1.56,.64,1);}
.ring-text{position:absolute;inset:0;display:grid;place-items:center;font-size:46px;font-weight:800;}
.ring-text small{font-size:22px;color:var(--text-2);}
.result-stats{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:26px;}
.result-stats>div{background:rgba(255,255,255,.04);padding:14px;border-radius:12px;border:1px solid var(--border);}
.result-stats strong{display:block;font-size:24px;color:var(--p-2);}
.result-stats span{font-size:11px;color:var(--text-2);}
.result-actions{display:flex;gap:10px;justify-content:center;flex-wrap:wrap;}
.confetti{position:absolute;inset:0;pointer-events:none;overflow:hidden;}
.confetti i{position:absolute;width:8px;height:14px;top:-20px;animation:fall 3s linear forwards;}
@keyframes fall{to{transform:translateY(120vh) rotate(720deg);opacity:0}}

/* Review */
.review-item{background:var(--surface);backdrop-filter:blur(20px);border:1px solid var(--border-2);border-radius:var(--r);padding:22px;margin-bottom:14px;border-right:4px solid var(--border);}
.review-item.r{border-right-color:var(--suc);}
.review-item.w{border-right-color:var(--dan);}
.review-item h3{font-size:16px;margin-bottom:12px;}
.ya{margin:8px 0;padding:10px;border-radius:10px;background:rgba(255,255,255,.04);font-size:14px;}
.ya.r{background:rgba(16,185,129,.15);color:var(--suc);}
.ya.w{background:rgba(239,68,68,.15);color:var(--dan);}
.explain{background:rgba(124,58,237,.1);padding:10px;border-radius:10px;font-size:13px;color:var(--text-2);margin-top:10px;border-right:3px solid var(--p);}

.toast{position:fixed;bottom:30px;left:50%;transform:translateX(-50%) translateY(100px);background:var(--grad);color:white;padding:14px 24px;border-radius:14px;font-weight:600;z-index:200;transition:.4s cubic-bezier(.34,1.56,.64,1);box-shadow:0 20px 40px rgba(124,58,237,.4);}
.toast.show{transform:translateX(-50%) translateY(0);}
.toast.warn{background:var(--warn);}
.toast.err{background:var(--dan);}

@media(max-width:768px){
  .hero-wrap{padding:30px 0;}
  .result-stats{grid-template-columns:repeat(3,1fr);}
  .question-card{padding:22px;}
  .exam-bar{flex-direction:column;align-items:stretch;}
}

