// ============ الحالة العامة ============
const S = {
  cfg: { subject:'موضوع عام', diff:'سهل', qCount:10 },
  transcript: '',
  relevantWords: [],
  sentences: [],
  concepts: [],
  questions: [],
  exam: { idx:0, answers:[], timer:0, int:null },
  // النظام التراكمي
  user: JSON.parse(localStorage.getItem('su_user') || '{"xp":0,"streak":0,"lastDay":null,"ach":[],"exams":0,"best":0,"totalCorrect":0,"totalQuestions":0}')
};

const $ = id => document.getElementById(id);
const L = (ar,...vars)=>ar.reduce((s,a,i)=>s+a+(vars[i]||''),'');

// ============ حفظ التقدم ============
function saveUser(){
  localStorage.setItem('su_user', JSON.stringify(S.user));
}

// ============ مؤثرات صوتية ============
const audioCtx = new (window.AudioContext || window.webkitAudioContext)();
function beep(f=440, d=.1, v=.1, t='sine'){
  try{
    const o = audioCtx.createOscillator();
    const g = audioCtx.createGain();
    o.connect(g); g.connect(audioCtx.destination);
    o.frequency.value = f; o.type = t;
    g.gain.setValueAtTime(v, audioCtx.currentTime);
    g.gain.exponentialRampToValueAtTime(.001, audioCtx.currentTime + d);
    o.start(); o.stop(audioCtx.currentTime + d);
  }catch(e){}
}
const sound = {
  correct: ()=>{ beep(523,.1); setTimeout(()=>beep(784,.15),80); },
  wrong: ()=> beep(200,.2,.15,'sawtooth'),
  click: ()=> beep(800,.05,.05),
  finish: ()=>{ beep(523,.1); setTimeout(()=>beep(659,.1),120); setTimeout(()=>beep(784,.2),240); },
  unlock: ()=>{ beep(659,.1); setTimeout(()=>beep(880,.15),100); setTimeout(()=>beep(1047,.2),200); },
  record: ()=> beep(440,.08,.08),
  stop: ()=> beep(880,.08,.08)
};

// ============ تحديث الإحصائيات ============
function updateStats(){
  const u = S.user;
  $('navXp').textContent = u.xp;
  $('navStreak').textContent = u.streak;
  $('statsCompleted').textContent = u.exams;
  const avg = u.exams > 0 ? Math.round((u.totalCorrect / u.totalQuestions) * 100) : 0;
  $('statsAvgScore').textContent = avg + '%';
  $('statsExams').textContent = u.exams;
  $('statsStreak').textContent = u.streak;
}

// ============ الإنجازات ============
const ACHS = [
  { id:'first', name:'البداية', desc:'أول امتحان', icon:'🎯', check:()=>S.user.exams>=1 },
  { id:'three', name:'متعلم نشيط', desc:'3 امتحانات', icon:'📚', check:()=>S.user.exams>=3 },
  { id:'five', name:'مثابر', desc:'5 امتحانات', icon:'💪', check:()=>S.user.exams>=5 },
  { id:'ten', name:'خبير', desc:'10 امتحانات', icon:'🏆', check:()=>S.user.exams>=10 },
  { id:'high', name:'ممتاز', desc:'نتيجة 100%', icon:'💯', check:()=>S.user.best===100 },
  { id:'good', name:'جيد جداً', desc:'نتيجة 90%+', icon:'⭐', check:()=>S.user.best>=90 },
  { id:'streak3', name:'منتظم', desc:'سلسلة 3 أيام', icon:'🔥', check:()=>S.user.streak>=3 },
  { id:'streak7', name:'أسطورة', desc:'سلسلة 7 أيام', icon:'🔥', check:()=>S.user.streak>=7 },
  { id:'xp100', name:'جامع نقاط', desc:'100 XP', icon:'💰', check:()=>S.user.xp>=100 },
  { id:'xp500', name:'جامع نقاط محترف', desc:'500 XP', icon:'💎', check:()=>S.user.xp>=500 }
];

function checkAchievements(){
  const newAch = [];
  ACHS.forEach(a => {
    if(!S.user.ach.includes(a.id) && a.check()){
      S.user.ach.push(a.id);
      newAch.push(a);
    }
  });
  if(newAch.length){
    saveUser();
    sound.unlock();
    showAchPop(newAch);
  }
}

function showAchPop(achs){
  const pop = $('newAchievement');
  const txt = $('newAchText');
  if(pop && achs.length){
    pop.style.display = 'inline-flex';
    txt.textContent = 'إنجاز جديد: ' + achs[0].name + ' ' + achs[0].icon;
    setTimeout(()=>{ pop.style.display = 'none'; }, 4000);
  }
}

// ============ تحديث الستريك ============
function updateStreak(){
  const today = new Date().toDateString();
  if(S.user.lastDay !== today){
    const y = new Date(); y.setDate(y.getDate() - 1);
    if(S.user.lastDay === y.toDateString()){
      S.user.streak++;
    } else if(S.user.lastDay !== null){
      S.user.streak = 1;
    } else {
      S.user.streak = 1;
    }
    S.user.lastDay = today;
    saveUser();
  }
}

// ============ Toast ============
function toast(msg, type=''){
  const t = $('toast');
  t.textContent = msg;
  t.className = 'toast show ' + type;
  setTimeout(() => t.className = 'toast', 2400);
}

// ============ Settings ============
document.querySelectorAll('[data-diff]').forEach(c => c.addEventListener('click', () => {
  document.querySelectorAll('[data-diff]').forEach(x=>x.classList.remove('active'));
  c.classList.add('active');
  S.cfg.diff = c.dataset.diff;
  sound.click();
}));
document.querySelectorAll('[data-q]').forEach(c => c.addEventListener('click', () => {
  document.querySelectorAll('[data-q]').forEach(x=>x.classList.remove('active'));
  c.classList.add('active');
  S.cfg.qCount = parseInt(c.dataset.q);
  sound.click();
}));
$('subjectInput').addEventListener('input', e => S.cfg.subject = e.target.value || 'موضوع عام');

// ============ Navigation ============
function go(id){
  if(S.exam.int && id!=='examScreen'){ clearInterval(S.exam.int); S.exam.int = null; }
  document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));
  $(id).classList.add('active');
  window.scrollTo({top:0, behavior:'smooth'});
}
document.querySelectorAll('[data-go]').forEach(el=>el.addEventListener('click',()=>{
  sound.click();
  go(el.dataset.go);
}));

// ============ Theme ============
$('themeToggle').addEventListener('click',()=>{
  const h=document.documentElement, n=h.dataset.theme==='dark'?'light':'dark';
  h.dataset.theme=n;
  $('themeToggle').textContent = n==='dark'?'🌙':'☀️';
  localStorage.setItem('s_theme', n);
});
if(localStorage.getItem('s_theme')){
  document.documentElement.dataset.theme = localStorage.getItem('s_theme');
  $('themeToggle').textContent = localStorage.getItem('s_theme')==='dark'?'🌙':'☀️';
}

// ============ شاشة التسجيل - Web Speech ============
let recognition = null;
let isRecording = false;
let recTimerStart = 0;
let recInterval = null;

function setupSpeech(){
  if(!('webkitSpeechRecognition' in window) && !('SpeechRecognition' in window)){
    toast('المتصفح لا يدعم التعرف على الصوت. استخدم الكتابة', 'warn');
    return false;
  }
  const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
  recognition = new SR();
  recognition.lang = 'ar-SA';
  recognition.continuous = true;
  recognition.interimResults = true;
  recognition.maxAlternatives = 1;

  let finalTxt = '';
  recognition.onresult = (e) => {
    let interim = '';
    for(let i=e.resultIndex; i<e.results.length; i++){
      const r = e.results[i];
      if(r.isFinal) finalTxt += r[0].transcript + ' ';
      else interim += r[0].transcript;
    }
    S.transcript = finalTxt;
    $('transcript').innerHTML = L(
      '<span class="final">', finalTxt, '</span>',
      interim ? '<span class="interim"> '+interim+'</span>' : ''
    );
    updateWordCount();
    autoScroll();
    if(finalTxt.trim().length > 30) $('btnFinish').disabled = false;
  };
  recognition.onerror = (e) => {
    console.error('Speech error:', e.error);
    if(e.error === 'not-allowed') toast('السماح بالميكروفون مطلوب', 'err');
    else if(e.error === 'no-speech') toast('لم أسمع شيئاً، حاول مرة أخرى', 'warn');
    else toast('خطأ في التعرف: ' + e.error, 'warn');
    stopRecording();
  };
  recognition.onend = () => {
    if(isRecording){
      try{ recognition.start(); }catch(e){}
    }
  };
  return true;
}

function autoScroll(){
  const t = $('transcript');
  if(t) t.scrollTop = t.scrollHeight;
}

function updateWordCount(){
  const words = S.transcript.trim().split(/\s+/).filter(w=>w.length>0);
  $('wordCount').textContent = words.length;
}

function startRecording(){
  if(!recognition) {
    if(!setupSpeech()) return;
  }
  try{
    recognition.start();
    isRecording = true;
    $('micBtn').classList.add('recording');
    document.querySelector('.pulse-ring').classList.add('active');
    $('recStatusText').textContent = '🔴 جاري الاستماع... تكلم بحرية';
    recTimerStart = Date.now();
    recInterval = setInterval(()=>{
      const sec = Math.floor((Date.now()-recTimerStart)/1000);
      const m = String(Math.floor(sec/60)).padStart(2,'0');
      const s = String(sec%60).padStart(2,'0');
      $('recTimer').textContent = m+':'+s;
    },1000);
    $('btnFinish').disabled = true;
    sound.record();
  }catch(e){
    toast('لا يمكن بدء التسجيل', 'err');
  }
}

function stopRecording(){
  if(recognition && isRecording){
    isRecording = false;
    try{ recognition.stop(); }catch(e){}
    $('micBtn').classList.remove('recording');
    document.querySelector('.pulse-ring').classList.remove('active');
    if(recInterval){ clearInterval(recInterval); recInterval = null; }
    $('recStatusText').textContent = '⏸️ متوقف - اضغط لإعادة التسجيل';
    sound.stop();
  }
}

function toggleRecording(){
  if(isRecording) stopRecording();
  else startRecording();
}

$('micBtn').addEventListener('click', toggleRecording);
$('btnClear').addEventListener('click', () => {
  if(!confirm('مسح كل ما قلته؟')) return;
  S.transcript = '';
  $('transcript').innerHTML = '<span class="placeholder">النص يظهر هنا أثناء الكلام...</span>';
  $('wordCount').textContent = '0';
  $('btnFinish').disabled = true;
});
$('backRecord').addEventListener('click', ()=>{
  stopRecording();
  go('homeScreen');
});

// ============ شاشة الكتابة ============
const ti = $('textInput');
ti.addEventListener('input', () => {
  const txt = ti.value;
  S.transcript = txt;
  const words = txt.trim().split(/\s+/).filter(w=>w.length>0);
  const sents = txt.split(/[.!?؟।]+/).filter(s=>s.trim().length>10);
  $('textWordCount').textContent = words.length;
  $('textCharCount').textContent = txt.length;
  $('textSentCount').textContent = sents.length;
  $('textAnalyze').disabled = words.length < 20;
});
$('textClear').addEventListener('click', ()=>{
  if(!confirm('مسح كل النص؟')) return;
  ti.value='';
  ti.dispatchEvent(new Event('input'));
});

// ============ أزرار الذهاب للتسجيل/الكتابة ============
$('goRecord').addEventListener('click', () => {
  $('recordTitle').textContent = 'سجّل شرحك لـ: '+S.cfg.subject;
  go('recordScreen');
  setTimeout(()=>{
    if(!recognition && !setupSpeech()) return;
    toast('اضغط الميكروفون لبدء التسجيل');
  },300);
});
$('goText').addEventListener('click', () => {
  $('textInput').value = '';
  ti.dispatchEvent(new Event('input'));
  go('textScreen');
});

// ============ المحلل النصي ============
const STOPWORDS = new Set([
  'في','من','إلى','على','عن','مع','هذا','هذه','ذلك','تلك','التي','الذي','الذين','اللتي','اللاتي','اللذان','هما','هم','هن','أن','إن','كان','كانت','كانوا','يكون','تكون','أكون','نكون','كل','بعض','جميع','غير','جدا','أكثر','أقل','كما','إذا','إذ','حين','حتى','لكن','بل','أو','ثم','إنما','قد','لقد','لقد','ليس','ليست','يجب','ينبغي','كما','هنا','هناك','عند','بين','فوق','تحت','أمام','خلف','بعد','قبل','حين','متى','أين','كيف','لماذا','ماذا','من','أي','كم','أي','كلا','كلتا','هكذا','كذلك','أيضا','أيضًا','الآن','اليوم','الذى','الذى','سوف','لقد','أنت','أنتم','أنتما','أنا','نحن','هو','هي','كتاب','يقول','قل','قال','تقول','نعم','لا','ليس','ليسوا','هناك','هنالك','يمكن','تستطيع','استطيع','وال','والـ','على','إليه','منه','منها','فيه','فيها','به','بها','له','لها','لهم','إليهم','اليهم','إليهم','لدي','لديه','لديها','ايضا','ربما','كثير','قليلا','جدا','تماما','كثيرا','بعض','عدة','بعض','لكن','غير','سوى','إلا','ماعدا','ما','هو','هي','ابي','امي','انا','تعرف','تعرفون','اعرف','نعرف','الذى','احد','كل','كلا','كلتا','يجب','ينبغي','كان','كانت','صاحب','صاحبة','جد','جدة','ابن','ابنة','اخ','اخت'
]);

function cleanWord(w){
  return w.replace(/[^\u0600-\u06FFa-zA-Z0-9]/g,'').trim();
}

function extractKeywords(text, max = 20){
  const words = text.split(/\s+/).map(cleanWord).filter(w=>w.length>=3 && !STOPWORDS.has(w) && !/^\d+$/.test(w));
  const freq = {};
  words.forEach(w => freq[w] = (freq[w]||0) + 1);
  const bigrams = {};
  for(let i=0; i<words.length-1; i++){
    const bg = words[i]+' '+words[i+1];
    if(!STOPWORDS.has(words[i]) && !STOPWORDS.has(words[i+1])){
      bigrams[bg] = (bigrams[bg]||0) + 2;
    }
  }
  const all = {};
  Object.entries(freq).forEach(([w,c])=>all[w]=c);
  Object.entries(bigrams).forEach(([w,c])=>all[w]=c);
  return Object.entries(all)
    .sort((a,b)=>b[1]-a[1])
    .slice(0, max)
    .map(([w])=>w);
}

function extractInformativeSentences(text, max=15){
  const sents = text.split(/[.!؟\n]+/).map(s=>s.trim()).filter(s=>s.length>=20 && s.length<=200);
  return sents.slice(0, max);
}

function extractConcepts(keywords, sentences){
  const concepts = [];
  keywords.slice(0, 15).forEach(kw => {
    const related = sentences.find(s => s.includes(kw));
    if(related){
      concepts.push({ term: kw, context: related });
    }
  });
  return concepts.slice(0, 10);
}

// ============ توليد الامتحان ============
function generateQuestions(){
  const text = S.transcript;
  const keywords = extractKeywords(text, 25);
  const allSents = extractInformativeSentences(text, 30);
  console.log('keywords:',keywords);
  console.log('sents:',allSents.length);

  let questions = [];
  const total = S.cfg.qCount;
  const targetMCQ = Math.floor(total * 0.4);
  const targetFill = Math.floor(total * 0.25);
  const targetTF = Math.floor(total * 0.2);
  const targetEssay = total - targetMCQ - targetFill - targetTF;

  // 1. MCQ
  let mcqAttempts = 0;
  while(questions.filter(q=>q.type==='mcq').length < targetMCQ && mcqAttempts < allSents.length*2){
    const sent = allSents[Math.floor(Math.random()*allSents.length)];
    if(!sent || sent.length<25) {mcqAttempts++;continue;}
    const kwInSent = keywords.filter(k => sent.includes(k));
    if(kwInSent.length === 0){mcqAttempts++;continue;}
    const correctWord = kwInSent[0];
    const sentShort = sent.length > 100 ? sent.substring(0, 100) + '...' : sent;
    const distractors = [];
    const otherKw = keywords.filter(k => k !== correctWord && !correctWord.includes(k) && !k.includes(correctWord));
    while(distractors.length < 3 && otherKw.length){
      const i = Math.floor(Math.random()*otherKw.length);
      const d = otherKw.splice(i,1)[0];
      if(!distractors.includes(d)) distractors.push(d);
    }
    while(distractors.length < 3){
      distractors.push('خيار آخر');
    }
    const opts = [correctWord, ...distractors.slice(0,3)];
    const shuffled = opts.slice().sort(()=>Math.random()-.5);
    const correctIdx = shuffled.indexOf(correctWord);
    questions.push({
      type: 'mcq',
      q: L('في شرحك لـ "<em>', S.cfg.subject, '</em>" ذكرت:<br>«<em>', sentShort, '</em>»<br><br>أي من التالي يتعلق بهذه الجملة؟'),
      opts: shuffled,
      idx: correctIdx,
      exp: 'ذكرتها في شرحك: «'+sent+'»'
    });
    mcqAttempts++;
  }

  // 2. Fill in blank
  let fillAttempts = 0;
  while(questions.filter(q=>q.type==='fill').length < targetFill && fillAttempts < allSents.length*2){
    const sent = allSents[Math.floor(Math.random()*allSents.length)];
    if(!sent || sent.length<25) {fillAttempts++;continue;}
    const kwInSent = keywords.filter(k => sent.includes(k) && k.length>=4);
    if(kwInSent.length === 0) {fillAttempts++;continue;}
    const word = kwInSent[0];
    const blanked = sent.replace(new RegExp('\\b'+word+'\\b','i'), '_____');
    if(!blanked.includes('_____')) {fillAttempts++;continue;}
    questions.push({
      type: 'fill',
      q: L('أكمل الفراغ من شرحك:<br><br>«<em>', blanked, '</em>»'),
      ans: word,
      exp: 'الكلمة الصحيحة: «'+word+'» من جملتك الأصلية'
    });
    fillAttempts++;
  }

  // 3. True/False
  let tfAttempts = 0;
  while(questions.filter(q=>q.type==='tf').length < targetTF && tfAttempts < allSents.length*3){
    const sent = allSents[Math.floor(Math.random()*allSents.length)];
    if(!sent || sent.length<25) {tfAttempts++;continue;}
    const direction = Math.random() < 0.5;
    if(direction){
      questions.push({
        type: 'tf',
        q: L('هل قلت في شرحك:<br>«<em>', sent, '</em>»؟'),
        ans: true,
        exp: 'نعم، هذه الجملة من شرحك'
      });
    } else {
      const kwInSent = keywords.filter(k => sent.includes(k) && k.length>=4);
      if(kwInSent.length === 0){tfAttempts++;continue;}
      const w = kwInSent[0];
      const otherKw = keywords.filter(k => k!==w && !w.includes(k) && !k.includes(w));
      if(otherKw.length === 0){tfAttempts++;continue;}
      const wrong = otherKw[Math.floor(Math.random()*otherKw.length)];
      const altered = sent.replace(w, wrong);
      if(altered === sent){tfAttempts++;continue;}
      questions.push({
        type: 'tf',
        q: L('هل قلت في شرحك:<br>«<em>', altered, '</em>»؟'),
        ans: false,
        exp: 'هذه الجملة معدّلة، الجملة الأصلية: «'+sent+'»'
      });
    }
    tfAttempts++;
  }

  // 4. Essay
  let essayAttempts = 0;
  const usedKw = [];
  while(questions.filter(q=>q.type==='essay').length < targetEssay && essayAttempts < keywords.length*2){
    const kw = keywords[Math.floor(Math.random()*keywords.length)];
    if(usedKw.includes(kw)){essayAttempts++;continue;}
    usedKw.push(kw);
    if(!kw || kw.length<3){essayAttempts++;continue;}
    const sent = allSents.find(s => s.includes(kw)) || '';
    questions.push({
      type: 'essay',
      q: L('اشرح بكلماتك مفهوم «<em>', kw, '</em>» كما ذكرته.<br><small style="color:var(--text-2)">استخدم الجملة الأصلية كدليل.</small>'),
      ref: kw,
      refSent: sent,
      exp: 'ذكرتها في شرحك: «'+(sent||kw)+'»'
    });
    essayAttempts++;
  }

  // سد الناقص
  while(questions.length < total && keywords.length){
    questions.push({
      type: 'mcq',
      q: 'أي من هذه المصطلحات ذكرتها في شرحك؟',
      opts: keywords.slice(0,4).sort(()=>Math.random()-.5),
      idx: 0,
      exp: 'كل هذه من شرحك'
    });
  }

  return questions.slice(0, total).sort(()=>Math.random()-.5);
}

